/* ============================================================
   EHAB TRUCK — East Africa Freight Platform
   Zero-dependency Node.js server (no npm install needed)
   Run:  node server.js   →  http://localhost:3000
   Data: saved permanently in data.json
   ============================================================ */
const http = require("http");
const fs = require("fs");
const path = require("path");
const crypto = require("crypto");

const PORT = process.env.PORT || 3000;
const DATA_FILE = path.join(__dirname, "data.json");

/* ---------------- DATA LAYER ---------------- */
let db;
function seed() {
  return {
    users: [
      { id: 1, name: "Ehab Admin", email: "admin@ehab.com", pass: hash("admin123"), role: "admin", phone: "+251900000000", approved: true, created: Date.now() }
    ],
    loads: [],
    nextUserId: 2,
    nextLoadId: 1000
  };
}
function load() {
  try { db = JSON.parse(fs.readFileSync(DATA_FILE, "utf8")); }
  catch { db = seed(); save(); }
}
function save() {
  const tmp = DATA_FILE + ".tmp";
  fs.writeFileSync(tmp, JSON.stringify(db, null, 2));
  fs.renameSync(tmp, DATA_FILE); // atomic write = no corruption
}
function hash(p) { return crypto.createHash("sha256").update("ehab:" + p).digest("hex"); }

/* ---------------- SESSIONS ---------------- */
const sessions = new Map(); // token -> userId
function newToken(uid) { const t = crypto.randomBytes(24).toString("hex"); sessions.set(t, uid); return t; }
function auth(req) {
  const t = (req.headers.authorization || "").replace("Bearer ", "");
  const uid = sessions.get(t);
  return uid ? db.users.find(u => u.id === uid) : null;
}

/* ---------------- HELPERS ---------------- */
function json(res, code, obj) {
  res.writeHead(code, { "Content-Type": "application/json" });
  res.end(JSON.stringify(obj));
}
function body(req) {
  return new Promise(resolve => {
    let b = "";
    req.on("data", c => (b += c));
    req.on("end", () => { try { resolve(JSON.parse(b || "{}")); } catch { resolve({}); } });
  });
}
const pub = u => ({ id: u.id, name: u.name, email: u.email, role: u.role, phone: u.phone, approved: u.approved });
const STATUSES = ["Posted", "Booked", "In Transit", "Delivered"];

/* ---------------- API ROUTES ---------------- */
async function api(req, res, url) {
  const seg = url.pathname.split("/").filter(Boolean); // ["api", ...]
  const method = req.method;

  /* --- AUTH --- */
  if (seg[1] === "register" && method === "POST") {
    const b = await body(req);
    if (!b.name || !b.email || !b.pass) return json(res, 400, { error: "Name, email and password are required." });
    if (db.users.some(u => u.email === b.email.toLowerCase())) return json(res, 400, { error: "This email is already registered." });
    const role = b.role === "carrier" ? "carrier" : "shipper";
    const u = { id: db.nextUserId++, name: b.name, email: b.email.toLowerCase(), pass: hash(b.pass), role, phone: b.phone || "", approved: role === "shipper", created: Date.now() };
    db.users.push(u); save();
    if (!u.approved) return json(res, 200, { pending: true, message: "Account created. Waiting for admin approval." });
    return json(res, 200, { token: newToken(u.id), user: pub(u) });
  }
  if (seg[1] === "login" && method === "POST") {
    const b = await body(req);
    const u = db.users.find(u => u.email === (b.email || "").toLowerCase() && u.pass === hash(b.pass || ""));
    if (!u) return json(res, 401, { error: "Wrong email or password." });
    if (!u.approved) return json(res, 403, { error: "Your carrier account is waiting for admin approval." });
    return json(res, 200, { token: newToken(u.id), user: pub(u) });
  }

  /* --- everything below requires login --- */
  const me = auth(req);
  if (!me) return json(res, 401, { error: "Please log in." });

  if (seg[1] === "me") return json(res, 200, { user: pub(me) });

  /* --- LOADS --- */
  if (seg[1] === "loads" && method === "GET") {
    let list = db.loads;
    if (me.role === "shipper") list = list.filter(l => l.shipperId === me.id);
    if (me.role === "carrier" && url.searchParams.get("mine") === "1") list = list.filter(l => l.carrierId === me.id);
    if (me.role === "carrier" && url.searchParams.get("mine") !== "1") list = list.filter(l => l.status === "Posted");
    const q = (url.searchParams.get("q") || "").toLowerCase();
    if (q) list = list.filter(l => (l.from + l.to + l.cargo + l.truck).toLowerCase().includes(q));
    return json(res, 200, { loads: list.slice().reverse().map(l => withNames(l)) });
  }
  if (seg[1] === "loads" && method === "POST" && seg.length === 2) {
    if (me.role !== "shipper" && me.role !== "admin") return json(res, 403, { error: "Only shippers can post loads." });
    const b = await body(req);
    if (!b.from || !b.to || !b.cargo || !b.priceETB || !b.date) return json(res, 400, { error: "Fill route, cargo, price and date." });
    if (b.from === b.to) return json(res, 400, { error: "Origin and destination must be different." });
    const l = {
      id: db.nextLoadId++, shipperId: me.id, from: b.from, to: b.to, cargo: b.cargo,
      truck: b.truck || "Dry cargo", weight: b.weight || "—",
      priceETB: +b.priceETB, priceUSD: +b.priceUSD || Math.round(+b.priceETB / 128),
      date: b.date, status: "Posted", carrierId: null, created: Date.now(),
      history: [{ status: "Posted", at: Date.now() }],
      paymentStatus: "Unpaid", paymentMethod: null, paymentNote: null, paidAt: null
    };
    db.loads.push(l); save();
    return json(res, 200, { load: withNames(l) });
  }
  if (seg[1] === "loads" && seg[3] === "book" && method === "POST") {
    if (me.role !== "carrier") return json(res, 403, { error: "Only carriers can book loads." });
    const l = db.loads.find(l => l.id === +seg[2]);
    if (!l) return json(res, 404, { error: "Load not found." });
    if (l.status !== "Posted") return json(res, 400, { error: "This load is already taken." });
    l.status = "Booked"; l.carrierId = me.id;
    l.history.push({ status: "Booked", at: Date.now() }); save();
    return json(res, 200, { load: withNames(l) });
  }
  if (seg[1] === "loads" && seg[3] === "status" && method === "POST") {
    const l = db.loads.find(l => l.id === +seg[2]);
    if (!l) return json(res, 404, { error: "Load not found." });
    const b = await body(req);
    if (!STATUSES.includes(b.status)) return json(res, 400, { error: "Invalid status." });
    const allowed = me.role === "admin" || (me.role === "carrier" && l.carrierId === me.id);
    if (!allowed) return json(res, 403, { error: "Not allowed." });
    l.status = b.status;
    l.history.push({ status: b.status, at: Date.now() }); save();
    return json(res, 200, { load: withNames(l) });
  }
  if (seg[1] === "loads" && method === "DELETE") {
    const i = db.loads.findIndex(l => l.id === +seg[2]);
    if (i < 0) return json(res, 404, { error: "Load not found." });
    const l = db.loads[i];
    if (me.role !== "admin" && !(me.role === "shipper" && l.shipperId === me.id && l.status === "Posted"))
      return json(res, 403, { error: "Not allowed." });
    db.loads.splice(i, 1); save();
    return json(res, 200, { ok: true });
  }

  /* --- PAYMENTS (manual: admin confirms bank/cash transfer) --- */
  if (seg[1] === "loads" && seg[3] === "payment" && seg[4] === "submit" && method === "POST") {
    const l = db.loads.find(l => l.id === +seg[2]);
    if (!l) return json(res, 404, { error: "Load not found." });
    if (!(me.role === "shipper" && l.shipperId === me.id) && me.role !== "admin")
      return json(res, 403, { error: "Only the shipper who posted this load can submit payment." });
    if (l.paymentStatus === "Paid") return json(res, 400, { error: "This order is already marked paid." });
    const b = await body(req);
    if (!b.method) return json(res, 400, { error: "Choose a payment method." });
    l.paymentStatus = "Pending Verification";
    l.paymentMethod = b.method;
    l.paymentNote = b.note || "";
    l.submittedAt = Date.now();
    save();
    return json(res, 200, { load: withNames(l) });
  }
  if (seg[1] === "loads" && seg[3] === "payment" && method === "POST") {
    if (me.role !== "admin") return json(res, 403, { error: "Only admin can confirm payments." });
    const l = db.loads.find(l => l.id === +seg[2]);
    if (!l) return json(res, 404, { error: "Load not found." });
    const b = await body(req);
    if (b.status === "Paid") {
      l.paymentStatus = "Paid";
      l.paymentMethod = b.method || "Manual";
      l.paymentNote = b.note || "";
      l.paidAt = Date.now();
    } else {
      l.paymentStatus = "Unpaid";
      l.paymentMethod = null; l.paymentNote = null; l.paidAt = null;
    }
    save();
    return json(res, 200, { load: withNames(l) });
  }

  /* --- ADMIN --- */
  if (seg[1] === "users" && method === "GET") {
    if (me.role !== "admin") return json(res, 403, { error: "Admin only." });
    return json(res, 200, { users: db.users.map(pub) });
  }
  if (seg[1] === "users" && seg[3] === "approve" && method === "POST") {
    if (me.role !== "admin") return json(res, 403, { error: "Admin only." });
    const u = db.users.find(u => u.id === +seg[2]);
    if (!u) return json(res, 404, { error: "User not found." });
    u.approved = true; save();
    return json(res, 200, { user: pub(u) });
  }
  if (seg[1] === "stats" && method === "GET") {
    const active = db.loads.filter(l => l.status !== "Delivered").length;
    const delivered = db.loads.filter(l => l.status === "Delivered");
    const paid = db.loads.filter(l => l.paymentStatus === "Paid");
    const unpaid = db.loads.filter(l => l.paymentStatus !== "Paid" && l.paymentStatus !== "Pending Verification");
    const pending = db.loads.filter(l => l.paymentStatus === "Pending Verification");
    return json(res, 200, {
      stats: {
        totalLoads: db.loads.length,
        active,
        delivered: delivered.length,
        revenueETB: delivered.reduce((s, l) => s + l.priceETB, 0),
        carriers: db.users.filter(u => u.role === "carrier").length,
        shippers: db.users.filter(u => u.role === "shipper").length,
        pendingApprovals: db.users.filter(u => !u.approved).length,
        paidCount: paid.length,
        unpaidCount: unpaid.length,
        pendingPaymentCount: pending.length,
        paidValueETB: paid.reduce((s, l) => s + l.priceETB, 0),
        unpaidValueETB: unpaid.reduce((s, l) => s + l.priceETB, 0)
      }
    });
  }

  json(res, 404, { error: "Unknown API route." });
}
function withNames(l) {
  const s = db.users.find(u => u.id === l.shipperId);
  const c = db.users.find(u => u.id === l.carrierId);
  return { ...l, shipperName: s ? s.name : "—", carrierName: c ? c.name : null };
}

/* ---------------- STATIC FILES (embedded — single file build) ---------------- */
const FILES = {"/app.js":"/* ============================================================\n   EHAB TRUCK — Frontend app (talks to the real API)\n   ============================================================ */\nlet TOKEN = null;\nlet ME = null;\nlet regRole = \"shipper\";\nlet authMode = \"login\";\nlet activeTab = null;\nconst STATUSES = [\"Posted\", \"Booked\", \"In Transit\", \"Delivered\"];\nconst CITIES = [\"Addis Ababa\",\"Adama\",\"Dire Dawa\",\"Hirna\",\"Jigjiga\",\"Moyale\",\"Djibouti\",\"Hargeisa\",\"Berbera\",\"Mogadishu\",\"Bosaso\"];\nconst CITY_COORDS = {\n  \"Addis Ababa\":[9.02,38.75], \"Adama\":[8.54,39.27], \"Dire Dawa\":[9.60,41.87],\n  \"Hirna\":[9.22,41.10], \"Jigjiga\":[9.35,42.80], \"Moyale\":[3.53,39.06],\n  \"Djibouti\":[11.59,43.15], \"Hargeisa\":[9.56,44.07], \"Berbera\":[10.44,45.01],\n  \"Mogadishu\":[2.04,45.34], \"Bosaso\":[11.28,49.18]\n};\nconst ST_COLOR = { \"Posted\":\"#2563EB\", \"Booked\":\"#F0B90B\", \"In Transit\":\"#16A34A\", \"Delivered\":\"#94A3B8\" };\nlet LOADCACHE = {};   // id -> load, filled on every render\nlet MAP = null;\n\n/* ---------------- API ---------------- */\nasync function api(path, method = \"GET\", data) {\n  const opt = { method, headers: {} };\n  if (TOKEN) opt.headers.Authorization = \"Bearer \" + TOKEN;\n  if (data) { opt.headers[\"Content-Type\"] = \"application/json\"; opt.body = JSON.stringify(data); }\n  const r = await fetch(\"/api/\" + path, opt);\n  const j = await r.json().catch(() => ({}));\n  if (!r.ok) throw new Error(j.error || \"Something went wrong.\");\n  return j;\n}\n\n/* ---------------- SHELL NAV ---------------- */\nconst $ = id => document.getElementById(id);\nfunction show(page) {\n  [\"landing\", \"authPage\", \"dash\"].forEach(p => $(p).classList.toggle(\"hidden\", p !== page));\n  window.scrollTo(0, 0);\n}\nfunction backToLanding() { show(\"landing\"); }\nfunction toast(msg) {\n  $(\"toastHost\").innerHTML = `<div class=\"toast\"><span class=\"dot\"></span>${msg}</div>`;\n  setTimeout(() => ($(\"toastHost\").innerHTML = \"\"), 2800);\n}\n\n/* ---------------- AUTH ---------------- */\nfunction showAuth(mode, role) {\n  show(\"authPage\");\n  if (mode === \"register\" && authMode !== \"register\") toggleAuth();\n  if (mode === \"login\" && authMode !== \"login\") toggleAuth();\n  if (role) pickRole(role);\n}\nfunction toggleAuth() {\n  authMode = authMode === \"login\" ? \"register\" : \"login\";\n  const reg = authMode === \"register\";\n  $(\"regOnly\").classList.toggle(\"hidden\", !reg);\n  $(\"authTitle\").textContent = reg ? \"Create your account\" : \"Log in\";\n  $(\"authSub\").textContent = reg ? \"Free for shippers. Carriers are verified by our team.\" : \"Welcome back to Ehab Truck.\";\n  $(\"authBtn\").textContent = reg ? \"Create account\" : \"Log in\";\n  $(\"switchTxt\").textContent = reg ? \"Already have an account?\" : \"New to Ehab Truck?\";\n  $(\"switchLink\").textContent = reg ? \"Log in\" : \"Create an account\";\n  hideErr();\n}\nfunction pickRole(r) {\n  regRole = r;\n  $(\"roleShipper\").classList.toggle(\"active\", r === \"shipper\");\n  $(\"roleCarrier\").classList.toggle(\"active\", r === \"carrier\");\n}\nfunction showErr(m) { const e = $(\"authErr\"); e.textContent = m; e.classList.remove(\"hidden\"); }\nfunction hideErr() { $(\"authErr\").classList.add(\"hidden\"); }\n\nasync function submitAuth() {\n  hideErr();\n  const email = $(\"fEmail\").value.trim(), pass = $(\"fPass\").value;\n  if (!email || !pass) return showErr(\"Enter your email and password.\");\n  try {\n    if (authMode === \"login\") {\n      const r = await api(\"login\", \"POST\", { email, pass });\n      startSession(r);\n    } else {\n      const name = $(\"fName\").value.trim(), phone = $(\"fPhone\").value.trim();\n      if (!name) return showErr(\"Enter your full name.\");\n      const r = await api(\"register\", \"POST\", { name, email, pass, phone, role: regRole });\n      if (r.pending) { toast(\"Account created — waiting for admin approval\"); toggleAuth(); return; }\n      startSession(r);\n    }\n  } catch (e) { showErr(e.message); }\n}\nfunction startSession(r) {\n  TOKEN = r.token; ME = r.user;\n  $(\"uName\").textContent = ME.name;\n  $(\"uRole\").textContent = ME.role;\n  $(\"uAvatar\").textContent = ME.name.trim()[0].toUpperCase();\n  buildNav();\n  show(\"dash\");\n  toast(`Welcome, ${ME.name.split(\" \")[0]}!`);\n}\nfunction logout() { TOKEN = null; ME = null; show(\"landing\"); }\n\n/* ---------------- NAVIGATION ---------------- */\nconst NAVS = {\n  shipper: [[\"overview\",\"🏠\",\"Overview\"],[\"myloads\",\"📦\",\"My orders\"],[\"post\",\"➕\",\"Post load\"],[\"map\",\"🗺️\",\"Live map\"]],\n  carrier: [[\"overview\",\"🏠\",\"Overview\"],[\"board\",\"📋\",\"Load board\"],[\"jobs\",\"🚛\",\"My jobs\"],[\"map\",\"🗺️\",\"Live map\"]],\n  admin:   [[\"overview\",\"📊\",\"Overview\"],[\"allloads\",\"📦\",\"All orders\"],[\"payments\",\"💳\",\"Payments\"],[\"map\",\"🗺️\",\"Live map\"],[\"users\",\"👥\",\"Users\"]]\n};\nfunction buildNav() {\n  const items = NAVS[ME.role];\n  $(\"snav\").innerHTML = items.map(([k,i,l]) =>\n    `<button data-k=\"${k}\" onclick=\"setTab('${k}')\">${i} ${l}</button>`).join(\"\");\n  $(\"mtabs\").innerHTML = items.map(([k,i,l]) =>\n    `<button data-k=\"${k}\" onclick=\"setTab('${k}')\"><span class=\"mi\">${i}</span>${l}</button>`).join(\"\");\n  setTab(items[0][0]);\n}\nfunction setTab(k) {\n  activeTab = k;\n  document.querySelectorAll(\"[data-k]\").forEach(b => b.classList.toggle(\"active\", b.dataset.k === k));\n  render();\n}\n\n/* ---------------- RENDER ---------------- */\nconst bClass = s => ({ \"Posted\":\"b-posted\",\"Booked\":\"b-booked\",\"In Transit\":\"b-transit\",\"Delivered\":\"b-delivered\" }[s]);\nconst payClass = s => s === \"Paid\" ? \"b-transit\" : s === \"Pending Verification\" ? \"b-posted\" : \"b-booked\";\nconst payLabel = s => s === \"Paid\" ? \"💳 Paid\" : s === \"Pending Verification\" ? \"⏳ Verifying\" : \"💳 Unpaid\";\nfunction progress(l) {\n  const i = STATUSES.indexOf(l.status);\n  return `<div class=\"progress\">${STATUSES.map((s,x)=>`<i class=\"${x<=i?\"on\":\"\"}\" title=\"${s}\"></i>`).join(\"\")}</div>`;\n}\nfunction loadCard(l, actions = \"\") {\n  LOADCACHE[l.id] = l;\n  actions = `<button class=\"btn ghost sm\" onclick=\"openDetail(${l.id})\">Details</button>` + actions;\n  return `<div class=\"lcard\">\n    <div class=\"top\">\n      <div><div class=\"lroute\">${l.from} <span class=\"arr\">→</span> ${l.to}</div><div class=\"lid\">LOAD #${l.id} · Pickup ${l.date}</div></div>\n      <div style=\"display:flex;flex-direction:column;gap:5px;align-items:flex-end\">\n        <span class=\"badge ${bClass(l.status)}\">${l.status}</span>\n        <span class=\"badge ${payClass(l.paymentStatus)}\">${payLabel(l.paymentStatus)}</span>\n      </div>\n    </div>\n    <div class=\"lmeta\">\n      <span>Cargo · <b>${esc(l.cargo)}</b></span><span>Truck · <b>${esc(l.truck)}</b></span>\n      <span>Weight · <b>${esc(l.weight)}</b></span>\n      <span>${l.carrierName ? \"Carrier · <b>\"+esc(l.carrierName)+\"</b>\" : \"Shipper · <b>\"+esc(l.shipperName)+\"</b>\"}</span>\n    </div>\n    <div class=\"lprice\">${l.priceETB.toLocaleString()} ETB <small>≈ $${l.priceUSD.toLocaleString()}</small></div>\n    ${progress(l)}\n    <div class=\"lactions\">${actions}</div>\n  </div>`;\n}\nconst esc = s => String(s ?? \"\").replace(/[<>&\"]/g, c => ({\"<\":\"&lt;\",\">\":\"&gt;\",\"&\":\"&amp;\",'\"':\"&quot;\"}[c]));\nconst head = (title, sub, extra=\"\") =>\n  `<div class=\"page-head\"><div><h2>${title}</h2><div class=\"sub\">${sub}</div></div>${extra}</div>`;\nconst emptyBox = (icon, msg, cta=\"\") =>\n  `<div class=\"empty\"><div class=\"big\">${icon}</div><p>${msg}</p>${cta ? `<div style=\"margin-top:16px\">${cta}</div>` : \"\"}</div>`;\n\nasync function render() {\n  const m = $(\"main\");\n  m.innerHTML = `<div class=\"empty\" style=\"border:none\">Loading…</div>`;\n  try {\n    if (activeTab === \"overview\") return renderOverview(m);\n    if (activeTab === \"myloads\")  return renderMyLoads(m);\n    if (activeTab === \"post\")     return renderPost(m);\n    if (activeTab === \"board\")    return renderBoard(m);\n    if (activeTab === \"jobs\")     return renderJobs(m);\n    if (activeTab === \"allloads\") return renderAllLoads(m);\n    if (activeTab === \"users\")    return renderUsers(m);\n    if (activeTab === \"map\")      return renderMap(m);\n    if (activeTab === \"payments\") return renderPayments(m);\n  } catch (e) { m.innerHTML = emptyBox(\"⚠️\", esc(e.message)); }\n}\n\n/* --- Overview (all roles) --- */\nasync function renderOverview(m) {\n  if (ME.role === \"admin\") {\n    const { stats } = await api(\"stats\");\n    const { loads } = await api(\"loads\");\n    m.innerHTML = head(\"Operations overview\", \"Live view of the whole platform\") + `\n      <div class=\"kpis\">\n        <div class=\"kpi\"><div class=\"kl\">Total loads</div><div class=\"kn\">${stats.totalLoads}</div></div>\n        <div class=\"kpi k-blue\"><div class=\"kl\">Active shipments</div><div class=\"kn\">${stats.active}</div></div>\n        <div class=\"kpi k-green\"><div class=\"kl\">Delivered</div><div class=\"kn\">${stats.delivered}</div></div>\n        <div class=\"kpi k-red\"><div class=\"kl\">Pending approvals</div><div class=\"kn\">${stats.pendingApprovals}</div></div>\n      </div>\n      <div class=\"kpis\">\n        <div class=\"kpi k-green\"><div class=\"kl\">Paid</div><div class=\"kn\">${stats.paidValueETB.toLocaleString()}<span style=\"font-size:14px;color:var(--muted)\"> ETB</span></div><div class=\"kl\">${stats.paidCount} order(s)</div></div>\n        <div class=\"kpi k-red\"><div class=\"kl\">Unpaid</div><div class=\"kn\">${stats.unpaidValueETB.toLocaleString()}<span style=\"font-size:14px;color:var(--muted)\"> ETB</span></div><div class=\"kl\">${stats.unpaidCount} order(s)</div></div>\n      </div>\n      ${loads.length ? `<div class=\"tablecard\"><table>\n        <tr><th>Load</th><th>Route</th><th>Cargo</th><th>Price (ETB)</th><th>Status</th></tr>\n        ${loads.slice(0,8).map(l=>`<tr><td>#${l.id}</td><td><b>${l.from} → ${l.to}</b></td><td>${esc(l.cargo)}</td><td>${l.priceETB.toLocaleString()}</td><td><span class=\"badge ${bClass(l.status)}\">${l.status}</span></td></tr>`).join(\"\")}\n      </table></div>` : emptyBox(\"📭\",\"No loads on the platform yet.\")}`;\n    return;\n  }\n  const mine = ME.role === \"shipper\" ? (await api(\"loads\")).loads : (await api(\"loads?mine=1\")).loads;\n  const active = mine.filter(l => l.status !== \"Delivered\");\n  const done = mine.filter(l => l.status === \"Delivered\");\n  const valueETB = mine.reduce((s,l)=>s+l.priceETB,0);\n  m.innerHTML = head(`Welcome, ${esc(ME.name.split(\" \")[0])} 👋`,\n      ME.role === \"shipper\" ? \"Here's how your cargo is moving\" : \"Here's how your trucks are doing\") + `\n    <div class=\"kpis\">\n      <div class=\"kpi\"><div class=\"kl\">${ME.role===\"shipper\"?\"My loads\":\"My jobs\"}</div><div class=\"kn\">${mine.length}</div></div>\n      <div class=\"kpi k-blue\"><div class=\"kl\">Active now</div><div class=\"kn\">${active.length}</div></div>\n      <div class=\"kpi k-green\"><div class=\"kl\">Delivered</div><div class=\"kn\">${done.length}</div></div>\n      <div class=\"kpi\"><div class=\"kl\">Total value</div><div class=\"kn\">${valueETB.toLocaleString()}<span style=\"font-size:14px;color:var(--muted)\"> ETB</span></div></div>\n    </div>\n    ${active.length\n      ? `<h3 style=\"margin-bottom:14px\">Active shipments</h3><div class=\"load-grid\">${active.map(l=>loadCard(l, ME.role===\"carrier\"?jobActions(l):\"\")).join(\"\")}</div>`\n      : emptyBox(ME.role===\"shipper\"?\"📦\":\"🚛\",\n          ME.role===\"shipper\" ? \"No active loads. Post one and carriers will see it instantly.\" : \"No active jobs. Check the load board for open freight.\",\n          `<button class=\"btn\" onclick=\"setTab('${ME.role===\"shipper\"?\"post\":\"board\"}')\">${ME.role===\"shipper\"?\"Post a load\":\"Open load board\"}</button>`)}`;\n}\n\n/* --- Shipper --- */\nasync function renderMyLoads(m) {\n  const { loads } = await api(\"loads\");\n  m.innerHTML = head(\"My loads\", `${loads.length} total`,\n    `<button class=\"btn\" onclick=\"setTab('post')\">➕ Post load</button>`) +\n    (loads.length\n      ? `<div class=\"load-grid\">${loads.map(l => loadCard(l, shipperPayActions(l))).join(\"\")}</div>`\n      : emptyBox(\"📦\",\"You haven't posted any loads yet.\", `<button class=\"btn\" onclick=\"setTab('post')\">Post your first load</button>`));\n}\nfunction shipperPayActions(l) {\n  let a = \"\";\n  if (l.status === \"Posted\") a += `<button class=\"btn danger sm\" onclick=\"delLoad(${l.id})\">Cancel load</button>`;\n  if (l.paymentStatus === \"Unpaid\") a += `<button class=\"btn success sm\" onclick=\"openSubmitPayment(${l.id})\">💳 I've paid — submit proof</button>`;\n  if (l.paymentStatus === \"Pending Verification\") a += `<button class=\"btn ghost sm\" onclick=\"openSubmitPayment(${l.id})\">Update payment proof</button>`;\n  return a;\n}\nfunction renderPost(m) {\n  const opts = sel => CITIES.map(c=>`<option ${c===sel?\"selected\":\"\"}>${c}</option>`).join(\"\");\n  m.innerHTML = head(\"Post a load\", \"Verified carriers will see it on the board instantly\") + `\n    <div class=\"lcard\" style=\"max-width:560px\">\n      <div class=\"field\"><label>From</label><select id=\"pFrom\">${opts(\"Addis Ababa\")}</select></div>\n      <div class=\"field\"><label>To</label><select id=\"pTo\">${opts(\"Djibouti\")}</select></div>\n      <div class=\"field\"><label>Cargo description</label><input id=\"pCargo\" placeholder=\"e.g. Cement bags — 400 pcs\"></div>\n      <div class=\"field\"><label>Truck type</label><select id=\"pTruck\">\n        <option>Dry cargo 40ft</option><option>Dry cargo 20ft</option><option>Flatbed</option>\n        <option>Refrigerated</option><option>Box truck</option><option>Tanker</option><option>Tipper</option></select></div>\n      <div class=\"field\"><label>Weight</label><input id=\"pWeight\" placeholder=\"e.g. 25 t\"></div>\n      <div class=\"field\"><label>Pickup date</label><input id=\"pDate\" type=\"date\"></div>\n      <div class=\"field\"><label>Price (ETB)</label><input id=\"pETB\" type=\"number\" placeholder=\"e.g. 180000\" oninput=\"autoUSD()\"></div>\n      <div class=\"field\"><label>Price (USD) <small style=\"color:var(--muted)\">auto ≈ ETB/128, you can edit</small></label><input id=\"pUSD\" type=\"number\" placeholder=\"auto\"></div>\n      <button class=\"btn block\" onclick=\"postLoad()\">Post to load board 🚀</button>\n    </div>`;\n}\nfunction autoUSD(){ const v=+$(\"pETB\").value; if(v) $(\"pUSD\").value = Math.round(v/128); }\nasync function postLoad() {\n  try {\n    const g = id => $(id).value;\n    await api(\"loads\",\"POST\",{ from:g(\"pFrom\"), to:g(\"pTo\"), cargo:g(\"pCargo\"), truck:g(\"pTruck\"),\n      weight:g(\"pWeight\"), date:g(\"pDate\"), priceETB:g(\"pETB\"), priceUSD:g(\"pUSD\") });\n    toast(\"Load posted ✓\"); setTab(\"myloads\");\n  } catch(e){ toast(e.message); }\n}\nasync function delLoad(id) {\n  try { await api(\"loads/\"+id, \"DELETE\"); toast(\"Load cancelled\"); render(); }\n  catch(e){ toast(e.message); }\n}\n\n/* --- Carrier --- */\nasync function renderBoard(m) {\n  const { loads } = await api(\"loads\");\n  m.innerHTML = head(\"Load board\", \"Open freight across the Horn of Africa\",\n    `<div class=\"searchbar\">🔍<input id=\"q\" placeholder=\"Search city, cargo…\" oninput=\"filterBoard()\"></div>`) +\n    `<div id=\"boardGrid\">` + (loads.length\n      ? `<div class=\"load-grid\">${loads.map(l => loadCard(l,\n          `<button class=\"btn success sm\" onclick=\"bookLoad(${l.id})\">Book this load ✓</button>`)).join(\"\")}</div>`\n      : emptyBox(\"🗺️\",\"No open loads right now. New freight is posted daily — check back soon.\")) + `</div>`;\n  window._boardCache = loads;\n}\nfunction filterBoard() {\n  const q = $(\"q\").value.toLowerCase();\n  const list = window._boardCache.filter(l => (l.from+l.to+l.cargo+l.truck).toLowerCase().includes(q));\n  $(\"boardGrid\").innerHTML = list.length\n    ? `<div class=\"load-grid\">${list.map(l => loadCard(l, `<button class=\"btn success sm\" onclick=\"bookLoad(${l.id})\">Book this load ✓</button>`)).join(\"\")}</div>`\n    : emptyBox(\"🔍\",\"No loads match your search.\");\n}\nasync function bookLoad(id) {\n  try { await api(`loads/${id}/book`, \"POST\"); toast(\"Load booked — safe trip! 🚛\"); setTab(\"jobs\"); }\n  catch(e){ toast(e.message); }\n}\nfunction jobActions(l) {\n  if (l.status === \"Booked\")     return `<button class=\"btn sm\" onclick=\"setStatus(${l.id},'In Transit')\">Start trip →</button>`;\n  if (l.status === \"In Transit\") return `<button class=\"btn success sm\" onclick=\"setStatus(${l.id},'Delivered')\">Mark delivered ✓</button>`;\n  return \"\";\n}\nasync function renderJobs(m) {\n  const { loads } = await api(\"loads?mine=1\");\n  m.innerHTML = head(\"My jobs\", `${loads.length} booked`) +\n    (loads.length\n      ? `<div class=\"load-grid\">${loads.map(l => loadCard(l, jobActions(l))).join(\"\")}</div>`\n      : emptyBox(\"🚛\",\"No jobs yet. Book a load from the board.\", `<button class=\"btn\" onclick=\"setTab('board')\">Open load board</button>`));\n}\nasync function setStatus(id, status) {\n  try { await api(`loads/${id}/status`, \"POST\", { status }); toast(\"Status: \" + status); render(); }\n  catch(e){ toast(e.message); }\n}\n\n/* --- Admin --- */\nasync function renderAllLoads(m) {\n  const { loads } = await api(\"loads\");\n  m.innerHTML = head(\"All loads\", `${loads.length} on the platform`) +\n    (loads.length\n      ? `<div class=\"load-grid\">${loads.map(l => loadCard(l, adminActions(l))).join(\"\")}</div>`\n      : emptyBox(\"📭\",\"No loads yet.\"));\n}\nfunction adminActions(l) {\n  const i = STATUSES.indexOf(l.status);\n  let a = \"\";\n  if (i < STATUSES.length - 1) a += `<button class=\"btn ghost sm\" onclick=\"setStatus(${l.id},'${STATUSES[i+1]}')\">Move to ${STATUSES[i+1]} →</button>`;\n  a += l.paymentStatus === \"Paid\"\n    ? `<button class=\"btn ghost sm\" onclick=\"openPaymentModal(${l.id})\">💳 Edit payment</button>`\n    : `<button class=\"btn success sm\" onclick=\"openPaymentModal(${l.id})\">💳 Mark as Paid</button>`;\n  a += `<button class=\"btn danger sm\" onclick=\"delLoad(${l.id})\">Delete</button>`;\n  return a;\n}\nasync function renderUsers(m) {\n  const { users } = await api(\"users\");\n  m.innerHTML = head(\"Users\", `${users.length} registered`) + `\n    <div class=\"tablecard\"><table>\n      <tr><th>Name</th><th>Role</th><th>Email</th><th>Phone</th><th>Status</th><th></th></tr>\n      ${users.map(u => `<tr>\n        <td><b>${esc(u.name)}</b></td><td style=\"text-transform:capitalize\">${u.role}</td>\n        <td>${esc(u.email)}</td><td>${esc(u.phone) || \"—\"}</td>\n        <td>${u.approved ? '<span class=\"badge b-transit\">Approved</span>' : '<span class=\"badge b-booked\">Pending</span>'}</td>\n        <td>${!u.approved ? `<button class=\"btn success sm\" onclick=\"approve(${u.id})\">Approve ✓</button>` : \"\"}</td>\n      </tr>`).join(\"\")}\n    </table></div>`;\n}\nasync function approve(id) {\n  try { await api(`users/${id}/approve`, \"POST\"); toast(\"Carrier approved ✓\"); render(); }\n  catch(e){ toast(e.message); }\n}\n\n/* ---------------- LIVE MAP ---------------- */\nasync function renderMap(m) {\n  // which loads to show depends on role\n  let loads;\n  if (ME.role === \"admin\")        loads = (await api(\"loads\")).loads;\n  else if (ME.role === \"shipper\") loads = (await api(\"loads\")).loads;\n  else { // carrier: my jobs + open board\n    const jobs = (await api(\"loads?mine=1\")).loads;\n    const open = (await api(\"loads\")).loads;\n    const seen = new Set(jobs.map(l => l.id));\n    loads = jobs.concat(open.filter(l => !seen.has(l.id)));\n  }\n  loads.forEach(l => (LOADCACHE[l.id] = l));\n\n  m.innerHTML = head(\"Live map\", `${loads.length} shipments across the Horn of Africa`) + `\n    <div class=\"mapbox\" id=\"mapbox\"></div>\n    <div class=\"map-legend\">\n      <span><i style=\"background:${ST_COLOR[\"Posted\"]}\"></i> Posted</span>\n      <span><i style=\"background:${ST_COLOR[\"Booked\"]}\"></i> Booked</span>\n      <span><i style=\"background:${ST_COLOR[\"In Transit\"]}\"></i> In Transit</span>\n      <span><i style=\"background:${ST_COLOR[\"Delivered\"]}\"></i> Delivered</span>\n      <span>🚛 = truck currently on the road</span>\n    </div>`;\n\n  if (typeof L === \"undefined\") {\n    $(\"mapbox\").innerHTML = `<div class=\"empty\" style=\"border:none;height:100%\">🌐 The map needs an internet connection to load. Everything else works offline.</div>`;\n    return;\n  }\n  if (MAP) { MAP.remove(); MAP = null; }\n  MAP = L.map(\"mapbox\").setView([8.6, 42.2], 6);\n  L.tileLayer(\"https://tile.openstreetmap.org/{z}/{x}/{y}.png\", {\n    attribution: '&copy; OpenStreetMap contributors', maxZoom: 18\n  }).addTo(MAP);\n\n  // city markers\n  const usedCities = new Set();\n  loads.forEach(l => { usedCities.add(l.from); usedCities.add(l.to); });\n  usedCities.forEach(c => {\n    const p = CITY_COORDS[c]; if (!p) return;\n    L.circleMarker(p, { radius: 6, color: \"#0F172A\", weight: 2, fillColor: \"#fff\", fillOpacity: 1 })\n      .addTo(MAP).bindTooltip(c, { permanent: false });\n  });\n\n  // shipment routes\n  loads.forEach(l => {\n    const a = CITY_COORDS[l.from], b = CITY_COORDS[l.to];\n    if (!a || !b) return;\n    const color = ST_COLOR[l.status];\n    const line = L.polyline([a, b], {\n      color, weight: 4, opacity: l.status === \"Delivered\" ? 0.45 : 0.85,\n      dashArray: l.status === \"Posted\" ? \"8 8\" : null\n    }).addTo(MAP);\n    line.bindPopup(popupHtml(l));\n    // truck marker in the middle if moving\n    if (l.status === \"In Transit\") {\n      const mid = [(a[0] + b[0]) / 2, (a[1] + b[1]) / 2];\n      const icon = L.divIcon({ html: \"🚛\", className: \"\", iconSize: [28, 28] });\n      L.marker(mid, { icon }).addTo(MAP).bindPopup(popupHtml(l));\n    }\n  });\n\n  if (usedCities.size) {\n    const pts = [...usedCities].map(c => CITY_COORDS[c]).filter(Boolean);\n    if (pts.length > 1) MAP.fitBounds(pts, { padding: [40, 40] });\n  }\n}\nfunction popupHtml(l) {\n  return `<b>#${l.id} · ${l.from} → ${l.to}</b><br>\n    ${esc(l.cargo)}<br>${l.priceETB.toLocaleString()} ETB · <b>${l.status}</b><br>\n    <a href=\"#\" onclick=\"openDetail(${l.id});return false\" style=\"color:#D40511;font-weight:700\">Open details →</a>`;\n}\n\n/* ---------------- ORDER DETAIL MODAL ---------------- */\nfunction openDetail(id) {\n  const l = LOADCACHE[id]; if (!l) return;\n  const fmt = t => new Date(t).toLocaleString(\"en-GB\", { day: \"2-digit\", month: \"short\", hour: \"2-digit\", minute: \"2-digit\" });\n  const doneSet = new Set((l.history || []).map(h => h.status));\n  const histMap = {}; (l.history || []).forEach(h => (histMap[h.status] = h.at));\n  $(\"modalHost\").innerHTML = `\n  <div class=\"modal-bg\" onclick=\"if(event.target===this)closeModal()\">\n    <div class=\"modal\">\n      <button class=\"close-x\" onclick=\"closeModal()\">✕</button>\n      <h3>Order #${l.id}</h3>\n      <div class=\"lroute\" style=\"font-size:19px\">${l.from} <span class=\"arr\">→</span> ${l.to}</div>\n      <span class=\"badge ${bClass(l.status)}\" style=\"margin-top:8px;display:inline-block\">${l.status}</span>\n      <span class=\"badge ${payClass(l.paymentStatus)}\" style=\"margin-top:8px;margin-left:6px;display:inline-block\">${payLabel(l.paymentStatus)}</span>\n      ${l.paymentStatus === \"Paid\" ? `<div style=\"color:var(--slate);font-size:13px;margin-top:8px\">Paid via <b>${esc(l.paymentMethod)}</b>${l.paymentNote ? \" · \" + esc(l.paymentNote) : \"\"}${l.paidAt ? \" · \" + new Date(l.paidAt).toLocaleDateString(\"en-GB\",{day:\"2-digit\",month:\"short\",year:\"numeric\"}) : \"\"}</div>` : \"\"}\n      ${l.paymentStatus === \"Pending Verification\" ? `<div style=\"color:var(--slate);font-size:13px;margin-top:8px\">Submitted via <b>${esc(l.paymentMethod)}</b>${l.paymentNote ? \" · \" + esc(l.paymentNote) : \"\"} — awaiting admin verification</div>` : \"\"}\n      <div class=\"detail-grid\">\n        <div><div class=\"dl\">Cargo</div><div class=\"dv\">${esc(l.cargo)}</div></div>\n        <div><div class=\"dl\">Truck type</div><div class=\"dv\">${esc(l.truck)}</div></div>\n        <div><div class=\"dl\">Weight</div><div class=\"dv\">${esc(l.weight)}</div></div>\n        <div><div class=\"dl\">Pickup date</div><div class=\"dv\">${l.date}</div></div>\n        <div><div class=\"dl\">Shipper</div><div class=\"dv\">${esc(l.shipperName)}</div></div>\n        <div><div class=\"dl\">Carrier</div><div class=\"dv\">${esc(l.carrierName) || \"— not booked yet\"}</div></div>\n        <div><div class=\"dl\">Price ETB</div><div class=\"dv\">${l.priceETB.toLocaleString()}</div></div>\n        <div><div class=\"dl\">Price USD</div><div class=\"dv\">$${l.priceUSD.toLocaleString()}</div></div>\n      </div>\n      <div class=\"dl\" style=\"color:var(--muted);font-size:12px;font-weight:700;text-transform:uppercase;margin-bottom:10px\">Tracking history</div>\n      <div class=\"timeline\">\n        ${STATUSES.map(s => `\n          <div class=\"tl-item ${doneSet.has(s) ? \"done\" : \"\"}\">\n            <div class=\"tl-dot\"></div>\n            <div class=\"tl-body\">\n              <div class=\"tl-st\">${s}</div>\n              <div class=\"tl-time\">${histMap[s] ? fmt(histMap[s]) : \"Pending\"}</div>\n            </div>\n          </div>`).join(\"\")}\n      </div>\n    </div>\n  </div>`;\n}\nfunction closeModal() { $(\"modalHost\").innerHTML = \"\"; }\n\n/* ---------------- PAYMENTS (admin) ---------------- */\nasync function renderPayments(m) {\n  const { loads } = await api(\"loads\");\n  loads.forEach(l => (LOADCACHE[l.id] = l));\n  const unpaid = loads.filter(l => l.paymentStatus !== \"Paid\" && l.paymentStatus !== \"Pending Verification\");\n  const pending = loads.filter(l => l.paymentStatus === \"Pending Verification\");\n  const paid = loads.filter(l => l.paymentStatus === \"Paid\");\n  const unpaidTotal = unpaid.reduce((s, l) => s + l.priceETB, 0);\n  const paidTotal = paid.reduce((s, l) => s + l.priceETB, 0);\n\n  m.innerHTML = head(\"Payments\", \"Confirm bank transfer or cash payments manually\") + `\n    <div class=\"kpis\">\n      <div class=\"kpi k-red\"><div class=\"kl\">Awaiting payment</div><div class=\"kn\">${unpaidTotal.toLocaleString()}<span style=\"font-size:14px;color:var(--muted)\"> ETB</span></div><div class=\"kl\">${unpaid.length} order(s)</div></div>\n      <div class=\"kpi k-blue\"><div class=\"kl\">Pending verification</div><div class=\"kn\">${pending.length}</div><div class=\"kl\">Submitted by shippers</div></div>\n      <div class=\"kpi k-green\"><div class=\"kl\">Confirmed paid</div><div class=\"kn\">${paidTotal.toLocaleString()}<span style=\"font-size:14px;color:var(--muted)\"> ETB</span></div><div class=\"kl\">${paid.length} order(s)</div></div>\n    </div>\n    <div class=\"tablecard\"><table>\n      <tr><th>Load</th><th>Shipper</th><th>Amount (ETB)</th><th>Status</th><th>Method</th><th></th></tr>\n      ${loads.map(l => `<tr>\n        <td>#${l.id}<br><span style=\"color:var(--muted);font-size:12px\">${esc(l.from)} → ${esc(l.to)}</span></td>\n        <td>${esc(l.shipperName)}</td>\n        <td>${l.priceETB.toLocaleString()}</td>\n        <td><span class=\"badge ${payClass(l.paymentStatus)}\">${payLabel(l.paymentStatus)}</span></td>\n        <td>${l.paymentMethod ? esc(l.paymentMethod) + (l.paymentNote ? \" · \"+esc(l.paymentNote) : \"\") : \"—\"}</td>\n        <td>${paymentRowActions(l)}</td>\n      </tr>`).join(\"\")}\n    </table></div>`;\n}\nfunction paymentRowActions(l) {\n  if (l.paymentStatus === \"Paid\") return `<button class=\"btn ghost sm\" onclick=\"openPaymentModal(${l.id})\">Edit</button>`;\n  if (l.paymentStatus === \"Pending Verification\")\n    return `<button class=\"btn success sm\" onclick=\"confirmPayment(${l.id},true)\">Approve ✓</button> <button class=\"btn danger sm\" onclick=\"revertPayment(${l.id})\">Reject</button>`;\n  return `<button class=\"btn success sm\" onclick=\"openPaymentModal(${l.id})\">Mark Paid</button>`;\n}\n\nfunction openPaymentModal(id) {\n  const l = LOADCACHE[id]; if (!l) return;\n  const isPaid = l.paymentStatus === \"Paid\";\n  $(\"modalHost\").innerHTML = `\n  <div class=\"modal-bg\" onclick=\"if(event.target===this)closeModal()\">\n    <div class=\"modal\">\n      <button class=\"close-x\" onclick=\"closeModal()\">✕</button>\n      <h3>${isPaid ? \"Edit payment\" : \"Confirm payment\"} — Order #${l.id}</h3>\n      <p style=\"color:var(--slate);font-size:14px;margin-bottom:14px\">${esc(l.shipperName)} · ${l.priceETB.toLocaleString()} ETB</p>\n      <div class=\"field\"><label>Payment method</label>\n        <select id=\"payMethod\">\n          <option ${l.paymentMethod===\"Bank Transfer\"?\"selected\":\"\"}>Bank Transfer</option>\n          <option ${l.paymentMethod===\"Cash\"?\"selected\":\"\"}>Cash</option>\n          <option ${l.paymentMethod===\"Telebirr\"?\"selected\":\"\"}>Telebirr</option>\n          <option ${l.paymentMethod===\"CBE Birr\"?\"selected\":\"\"}>CBE Birr</option>\n          <option ${l.paymentMethod===\"Other\"?\"selected\":\"\"}>Other</option>\n        </select>\n      </div>\n      <div class=\"field\"><label>Reference / note (optional)</label>\n        <input id=\"payNote\" placeholder=\"e.g. Transaction ID, sender name\" value=\"${l.paymentNote ? esc(l.paymentNote) : \"\"}\"></div>\n      <button class=\"btn success block\" onclick=\"confirmPayment(${l.id})\">✓ Confirm as Paid</button>\n      ${isPaid ? `<button class=\"btn ghost block\" style=\"margin-top:8px\" onclick=\"revertPayment(${l.id})\">Revert to Unpaid</button>` : \"\"}\n    </div>\n  </div>`;\n}\nasync function confirmPayment(id, quick) {\n  try {\n    if (quick) {\n      const l = LOADCACHE[id];\n      await api(`loads/${id}/payment`, \"POST\", { status: \"Paid\", method: l.paymentMethod || \"Manual\", note: l.paymentNote || \"\" });\n      toast(\"Payment approved ✓\"); render(); return;\n    }\n    await api(`loads/${id}/payment`, \"POST\", { status: \"Paid\", method: $(\"payMethod\").value, note: $(\"payNote\").value });\n    toast(\"Payment confirmed ✓\"); closeModal(); render();\n  } catch(e){ toast(e.message); }\n}\nasync function revertPayment(id) {\n  try {\n    await api(`loads/${id}/payment`, \"POST\", { status: \"Unpaid\" });\n    toast(\"Marked unpaid\"); closeModal(); render();\n  } catch(e){ toast(e.message); }\n}\n\n/* ---------------- SHIPPER: submit payment proof ---------------- */\nfunction openSubmitPayment(id) {\n  const l = LOADCACHE[id]; if (!l) return;\n  $(\"modalHost\").innerHTML = `\n  <div class=\"modal-bg\" onclick=\"if(event.target===this)closeModal()\">\n    <div class=\"modal\">\n      <button class=\"close-x\" onclick=\"closeModal()\">✕</button>\n      <h3>Submit payment proof — Order #${l.id}</h3>\n      <p style=\"color:var(--slate);font-size:14px;margin-bottom:14px\">${l.priceETB.toLocaleString()} ETB for ${l.from} → ${l.to}. After you submit, our team verifies it — usually within 24 hours.</p>\n      <div class=\"field\"><label>How did you pay?</label>\n        <select id=\"subMethod\">\n          <option>Bank Transfer</option><option>Cash</option><option>Telebirr</option><option>CBE Birr</option><option>Other</option>\n        </select>\n      </div>\n      <div class=\"field\"><label>Reference / transaction ID (optional)</label>\n        <input id=\"subNote\" placeholder=\"e.g. FT23198231 or sender name\"></div>\n      <button class=\"btn success block\" onclick=\"submitPayment(${l.id})\">Submit for verification ✓</button>\n    </div>\n  </div>`;\n}\nasync function submitPayment(id) {\n  try {\n    await api(`loads/${id}/payment/submit`, \"POST\", { method: $(\"subMethod\").value, note: $(\"subNote\").value });\n    toast(\"Payment submitted — awaiting verification ⏳\"); closeModal(); render();\n  } catch(e){ toast(e.message); }\n}\n","/img/logo-mark.svg":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 72 72\" width=\"72\" height=\"72\">\n  <rect width=\"72\" height=\"72\" rx=\"18\" fill=\"#FFCC00\"/>\n  <g fill=\"#0F172A\">\n    <rect x=\"10\" y=\"22\" width=\"32\" height=\"24\" rx=\"3\"/>\n    <path d=\"M42 28h12l8 9v9H42z\"/>\n    <circle cx=\"21\" cy=\"50\" r=\"6.5\"/><circle cx=\"50\" cy=\"50\" r=\"6.5\"/>\n  </g>\n  <circle cx=\"21\" cy=\"50\" r=\"2.6\" fill=\"#FFCC00\"/><circle cx=\"50\" cy=\"50\" r=\"2.6\" fill=\"#FFCC00\"/>\n  <rect x=\"46\" y=\"31\" width=\"8\" height=\"6\" rx=\"1\" fill=\"#FFCC00\"/>\n</svg>\n","/img/logo.svg":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 340 80\" width=\"340\" height=\"80\">\n  <rect x=\"4\" y=\"8\" width=\"64\" height=\"64\" rx=\"16\" fill=\"#FFCC00\"/>\n  <g fill=\"#0F172A\">\n    <rect x=\"12\" y=\"26\" width=\"30\" height=\"22\" rx=\"3\"/>\n    <path d=\"M42 32h11l7 8v8H42z\"/>\n    <circle cx=\"22\" cy=\"52\" r=\"6\"/><circle cx=\"48\" cy=\"52\" r=\"6\"/>\n  </g>\n  <circle cx=\"22\" cy=\"52\" r=\"2.4\" fill=\"#FFCC00\"/><circle cx=\"48\" cy=\"52\" r=\"2.4\" fill=\"#FFCC00\"/>\n  <rect x=\"46\" y=\"35\" width=\"7\" height=\"5\" rx=\"1\" fill=\"#FFCC00\"/>\n  <text x=\"82\" y=\"52\" font-family=\"Arial Black, Arial, sans-serif\" font-weight=\"900\" font-size=\"34\" fill=\"#0F172A\">EHAB<tspan fill=\"#D40511\">TRUCK</tspan></text>\n  <text x=\"84\" y=\"68\" font-family=\"Arial, sans-serif\" font-weight=\"600\" font-size=\"11\" letter-spacing=\"3\" fill=\"#94A3B8\">EAST AFRICA FREIGHT</text>\n</svg>\n","/img/sample-highway.svg":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 640 360\">\n  <defs><linearGradient id=\"sky\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n    <stop offset=\"0\" stop-color=\"#FFE9A3\"/><stop offset=\"1\" stop-color=\"#FFD34D\"/></linearGradient></defs>\n  <rect width=\"640\" height=\"360\" fill=\"url(#sky)\"/>\n  <circle cx=\"520\" cy=\"80\" r=\"42\" fill=\"#FFF6D6\"/>\n  <path d=\"M0 240 L140 170 L260 240 Z\" fill=\"#E8B84B\" opacity=\".7\"/>\n  <path d=\"M180 240 L340 150 L500 240 Z\" fill=\"#D9A63C\" opacity=\".8\"/>\n  <rect y=\"240\" width=\"640\" height=\"120\" fill=\"#3B4351\"/>\n  <rect y=\"292\" width=\"640\" height=\"8\" fill=\"none\" stroke=\"#FFCC00\" stroke-width=\"6\" stroke-dasharray=\"38 30\"/>\n  <g>\n    <rect x=\"120\" y=\"196\" width=\"230\" height=\"86\" rx=\"8\" fill=\"#0F172A\"/>\n    <rect x=\"132\" y=\"210\" width=\"206\" height=\"40\" rx=\"4\" fill=\"#1E293B\"/>\n    <text x=\"237\" y=\"238\" font-family=\"Arial Black, Arial\" font-weight=\"900\" font-size=\"26\" fill=\"#FFCC00\" text-anchor=\"middle\">EHAB TRUCK</text>\n    <path d=\"M350 216 h64 l34 34 v32 h-98 z\" fill=\"#D40511\"/>\n    <rect x=\"384\" y=\"224\" width=\"26\" height=\"20\" rx=\"2\" fill=\"#BFE3FF\"/>\n    <circle cx=\"168\" cy=\"288\" r=\"20\" fill=\"#0F172A\"/><circle cx=\"168\" cy=\"288\" r=\"8\" fill=\"#94A3B8\"/>\n    <circle cx=\"252\" cy=\"288\" r=\"20\" fill=\"#0F172A\"/><circle cx=\"252\" cy=\"288\" r=\"8\" fill=\"#94A3B8\"/>\n    <circle cx=\"404\" cy=\"288\" r=\"20\" fill=\"#0F172A\"/><circle cx=\"404\" cy=\"288\" r=\"8\" fill=\"#94A3B8\"/>\n  </g>\n  <text x=\"16\" y=\"346\" font-family=\"Arial\" font-size=\"12\" fill=\"#ffffff\" opacity=\".85\">SAMPLE IMAGE — replace with a real photo</text>\n</svg>\n","/img/sample-port.svg":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 640 360\">\n  <rect width=\"640\" height=\"360\" fill=\"#DCEDF7\"/>\n  <rect y=\"260\" width=\"640\" height=\"100\" fill=\"#4E9DC4\"/>\n  <rect y=\"230\" width=\"640\" height=\"34\" fill=\"#8C9AA8\"/>\n  <g stroke=\"#0F172A\" stroke-width=\"10\" fill=\"none\">\n    <path d=\"M120 230 V60 H400\"/><path d=\"M400 60 V110\"/>\n  </g>\n  <rect x=\"382\" y=\"110\" width=\"36\" height=\"26\" fill=\"#D40511\"/>\n  <g>\n    <rect x=\"180\" y=\"182\" width=\"110\" height=\"48\" fill=\"#D40511\"/>\n    <rect x=\"296\" y=\"182\" width=\"110\" height=\"48\" fill=\"#FFCC00\"/>\n    <rect x=\"238\" y=\"134\" width=\"110\" height=\"48\" fill=\"#2563EB\"/>\n    <g fill=\"#0F172A\" opacity=\".25\">\n      <rect x=\"188\" y=\"188\" width=\"4\" height=\"36\"/><rect x=\"206\" y=\"188\" width=\"4\" height=\"36\"/><rect x=\"224\" y=\"188\" width=\"4\" height=\"36\"/>\n      <rect x=\"304\" y=\"188\" width=\"4\" height=\"36\"/><rect x=\"322\" y=\"188\" width=\"4\" height=\"36\"/><rect x=\"340\" y=\"188\" width=\"4\" height=\"36\"/>\n    </g>\n  </g>\n  <text x=\"16\" y=\"346\" font-family=\"Arial\" font-size=\"12\" fill=\"#0F172A\" opacity=\".7\">SAMPLE IMAGE — replace with a real photo (Djibouti / Berbera port)</text>\n</svg>\n","/img/sample-warehouse.svg":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 640 360\">\n  <rect width=\"640\" height=\"360\" fill=\"#F1E9D6\"/>\n  <rect y=\"280\" width=\"640\" height=\"80\" fill=\"#C9BFA6\"/>\n  <path d=\"M60 280 V120 L320 60 L580 120 V280 Z\" fill=\"#E7DCC2\" stroke=\"#B8AD92\" stroke-width=\"4\"/>\n  <rect x=\"250\" y=\"170\" width=\"140\" height=\"110\" fill=\"#5B6472\"/>\n  <g>\n    <rect x=\"120\" y=\"216\" width=\"52\" height=\"64\" fill=\"#D9A63C\"/>\n    <rect x=\"120\" y=\"216\" width=\"52\" height=\"20\" fill=\"#C08F2B\"/>\n    <rect x=\"468\" y=\"200\" width=\"60\" height=\"80\" fill=\"#D9A63C\"/>\n    <rect x=\"468\" y=\"200\" width=\"60\" height=\"24\" fill=\"#C08F2B\"/>\n    <rect x=\"404\" y=\"240\" width=\"52\" height=\"40\" fill=\"#D9A63C\"/>\n  </g>\n  <text x=\"320\" y=\"140\" font-family=\"Arial Black, Arial\" font-weight=\"900\" font-size=\"22\" fill=\"#8A6D00\" text-anchor=\"middle\" opacity=\".6\">EHAB CARGO DEPOT</text>\n  <text x=\"16\" y=\"346\" font-family=\"Arial\" font-size=\"12\" fill=\"#0F172A\" opacity=\".6\">SAMPLE IMAGE — replace with a real photo</text>\n</svg>\n","/index.html":"<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Ehab Truck Cargo — East Africa Freight & Load Board</title>\n<meta name=\"description\" content=\"Post loads and book trucks across Ethiopia, Djibouti and Somalia. Full truck load, live tracking, transparent ETB/USD pricing.\">\n<meta name=\"theme-color\" content=\"#FFCC00\">\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n<link href=\"https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@600;700;800&family=Inter:wght@400;500;600;700&display=swap\" rel=\"stylesheet\">\n<link rel=\"icon\" type=\"image/svg+xml\" href=\"img/logo-mark.svg\">\n<link rel=\"stylesheet\" href=\"styles.css\">\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.css\">\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.js\"></script>\n</head>\n<body>\n\n<!-- ================= LANDING ================= -->\n<div id=\"landing\">\n  <nav class=\"topnav\"><div class=\"wrap topnav-in\">\n    <div class=\"brand\"><img src=\"img/logo-mark.svg\" class=\"brand-mark-img\" alt=\"Ehab Truck\">Ehab<span class=\"red\">Truck</span><span class=\"brand-sub\">Cargo</span></div>\n    <div class=\"nav-links\">\n      <a href=\"#routes\">Routes</a><a href=\"#features\">Platform</a><a href=\"#fleet\">Fleet</a><a href=\"#how\">How it works</a><a href=\"#policy\">Policy</a><a href=\"#news\">News</a>\n    </div>\n    <div style=\"display:flex;gap:10px\">\n      <button class=\"btn ghost\" onclick=\"showAuth('login')\">Log in</button>\n      <button class=\"btn\" onclick=\"showAuth('register')\">Get started</button>\n    </div>\n  </div></nav>\n\n  <header class=\"hero\"><div class=\"wrap hero-in\">\n    <div>\n      <span class=\"pill\">🇪🇹 Ethiopia · 🇩🇯 Djibouti · 🇸🇴 Somalia</span>\n      <h1>The load board for the <span class=\"hl\">Horn of Africa</span></h1>\n      <p class=\"lead\">Ehab Truck connects cargo owners with verified truck operators. Post a load in one minute, book a truck in one click, and track every kilometre to delivery.</p>\n      <div class=\"hero-cta\">\n        <button class=\"btn\" onclick=\"showAuth('register','shipper')\">Post a load — free</button>\n        <button class=\"btn dark\" onclick=\"showAuth('register','carrier')\">Drive with us</button>\n      </div>\n      <div class=\"trustline\">\n        <div><b>6+</b>Daily corridors</div>\n        <div><b>3</b>Countries</div>\n        <div><b>24/7</b>Dispatch</div>\n        <div><b>0 ETB</b>Posting fee</div>\n      </div>\n    </div>\n    <div class=\"hero-card\">\n      <div class=\"hc-title\">Load board <span class=\"hc-live\">Live</span></div>\n      <div class=\"hc-row\"><div class=\"hc-route\">Addis Ababa → Djibouti<span>Coffee · 24 t · 40ft</span></div><div class=\"hc-price\">185,000 ETB<small>≈ $1,450</small></div></div>\n      <div class=\"hc-row\"><div class=\"hc-route\">Dire Dawa → Djibouti<span>Perishables · 8 t · Reefer</span></div><div class=\"hc-price\">95,000 ETB<small>≈ $740</small></div></div>\n      <div class=\"hc-row\"><div class=\"hc-route\">Addis Ababa → Hargeisa<span>Electronics · 12 t · Box</span></div><div class=\"hc-price\">210,000 ETB<small>≈ $1,640</small></div></div>\n      <div class=\"hc-row\"><div class=\"hc-route\">Hargeisa → Berbera<span>Containers · Port link</span></div><div class=\"hc-price\">48,000 ETB<small>≈ $375</small></div></div>\n      <img src=\"img/sample-highway.svg\" alt=\"Ehab Truck on the highway\" style=\"width:100%;border-radius:18px;margin-top:16px;box-shadow:var(--shadow-lg)\">\n    </div>\n  </div></header>\n\n  <section class=\"land\" id=\"routes\"><div class=\"wrap\">\n    <div class=\"sec-kicker\">Corridors</div>\n    <h2 class=\"sec-title\">Routes we run every day</h2>\n    <div class=\"route-strip\"><div class=\"rt\">Addis Ababa <span class=\"arr\">→</span> Djibouti</div><div class=\"rmeta\"><span>Distance <b>~910 km</b></span><span>Transit <b>2–3 days</b></span><span><b>Import/Export corridor</b></span></div></div>\n    <div class=\"route-strip\"><div class=\"rt\">Adama <span class=\"arr\">→</span> Djibouti</div><div class=\"rmeta\"><span>Distance <b>~815 km</b></span><span>Transit <b>2 days</b></span><span><b>Containers & fuel</b></span></div></div>\n    <div class=\"route-strip\"><div class=\"rt\">Dire Dawa <span class=\"arr\">→</span> Djibouti</div><div class=\"rmeta\"><span>Distance <b>~440 km</b></span><span>Transit <b>1 day</b></span><span><b>Fast lane</b></span></div></div>\n    <div class=\"route-strip\"><div class=\"rt\">Addis Ababa <span class=\"arr\">→</span> Hargeisa</div><div class=\"rmeta\"><span>Distance <b>~1,050 km</b></span><span>Transit <b>3 days</b></span><span><b>Via Tog Wajaale</b></span></div></div>\n    <div class=\"route-strip\"><div class=\"rt\">Hargeisa <span class=\"arr\">→</span> Berbera</div><div class=\"rmeta\"><span>Distance <b>~160 km</b></span><span>Transit <b>Same day</b></span><span><b>Berbera Port link</b></span></div></div>\n    <div class=\"route-strip\"><div class=\"rt\">Addis Ababa <span class=\"arr\">→</span> Moyale</div><div class=\"rmeta\"><span>Distance <b>~775 km</b></span><span>Transit <b>2–3 days</b></span><span><b>Southern corridor</b></span></div></div>\n  </div></section>\n\n  <section class=\"land\" id=\"features\" style=\"background:#fff\"><div class=\"wrap\">\n    <div class=\"sec-kicker\">Platform</div>\n    <h2 class=\"sec-title\">Built like the big freight platforms</h2>\n    <div class=\"grid3\">\n      <div class=\"feature\"><div class=\"ic\">📦</div><h3>Smart load board</h3><p>Live marketplace where shippers post full truck loads and verified carriers book instantly — no phone chains, no middlemen.</p></div>\n      <div class=\"feature\"><div class=\"ic\">🛰️</div><h3>Shipment tracking</h3><p>Every load moves through Posted → Booked → In Transit → Delivered, with a timestamped history for every step.</p></div>\n      <div class=\"feature\"><div class=\"ic\">💰</div><h3>ETB + USD pricing</h3><p>Every price is shown in Ethiopian Birr and US Dollars before booking. Nothing changes at the border or the port.</p></div>\n      <div class=\"feature\"><div class=\"ic\">✅</div><h3>Verified carriers</h3><p>Truck operators are reviewed and approved by the Ehab team before they can accept their first load.</p></div>\n      <div class=\"feature\"><div class=\"ic\">🛃</div><h3>Border expertise</h3><p>Daily operations through Galafi, Dewele and Tog Wajaale crossings, plus Djibouti and Berbera port handling.</p></div>\n      <div class=\"feature\"><div class=\"ic\">📊</div><h3>Real dashboard</h3><p>Shippers, carriers and admins each get a purpose-built dashboard with live KPIs — not a spreadsheet.</p></div>\n    </div>\n  </div></section>\n\n  <section class=\"land\" id=\"fleet\" style=\"background:#fff\"><div class=\"wrap\">\n    <div class=\"sec-kicker\">Our operation</div>\n    <h2 class=\"sec-title\">From depot to port</h2>\n    <div class=\"grid3\">\n      <figure class=\"photo-card\"><img src=\"img/sample-highway.svg\" alt=\"Ehab truck on the Addis–Djibouti highway\">\n        <figcaption>On the Addis Ababa – Djibouti corridor</figcaption></figure>\n      <figure class=\"photo-card\"><img src=\"img/sample-port.svg\" alt=\"Container handling at the port\">\n        <figcaption>Container handling — Djibouti &amp; Berbera ports</figcaption></figure>\n      <figure class=\"photo-card\"><img src=\"img/sample-warehouse.svg\" alt=\"Cargo depot loading\">\n        <figcaption>Loading at the Adama cargo depot</figcaption></figure>\n    </div>\n  </div></section>\n\n  <section class=\"land\" id=\"how\"><div class=\"wrap\">\n    <div class=\"sec-kicker\">How it works</div>\n    <h2 class=\"sec-title\">From posting to delivery</h2>\n    <div class=\"grid3\">\n      <div class=\"feature\"><div class=\"ic\">1️⃣</div><h3>Post your load</h3><p>Route, cargo, truck type, pickup date and your price in ETB. Takes one minute, costs nothing.</p></div>\n      <div class=\"feature\"><div class=\"ic\">2️⃣</div><h3>A carrier books it</h3><p>Verified truck operators see your load on the board and book it in one click. You see who's carrying your cargo.</p></div>\n      <div class=\"feature\"><div class=\"ic\">3️⃣</div><h3>Track to delivery</h3><p>The carrier updates the trip status live. You watch your cargo move from pickup to delivered.</p></div>\n    </div>\n    <div style=\"margin-top:56px\">\n      <div class=\"cta-band\">\n        <div><h2>Ready to move cargo?</h2><p>Join Ehab Truck today — free for shippers.</p></div>\n        <button class=\"btn\" onclick=\"showAuth('register')\">Create free account</button>\n      </div>\n    </div>\n  </div></section>\n\n  <section class=\"land\" id=\"policy\" style=\"background:#fff\"><div class=\"wrap\">\n    <div class=\"sec-kicker\">Important customer document</div>\n    <h2 class=\"sec-title\">Service policy</h2>\n    <div class=\"policy-card\">\n      <p style=\"color:var(--slate);font-size:15px;max-width:640px\">Read our booking rules, payment verification process, cargo handling guidelines, and route coverage before placing a shipment.</p>\n      <ul class=\"policy-list\">\n        <li>📋 <div><b>Booking requirements</b> — accurate cargo description, weight, and pickup date required at posting.</div></li>\n        <li>💳 <div><b>Payment rules</b> — payments are confirmed manually by admin after bank transfer, cash, or mobile money; verification usually completes within 24 hours.</div></li>\n        <li>📦 <div><b>Claims process</b> — report any cargo damage or delay through Contact within 48 hours of delivery.</div></li>\n        <li>📞 <div><b>Support contacts</b> — dispatch is reachable by phone/WhatsApp during business hours, 7 days a week.</div></li>\n      </ul>\n      <div class=\"stats\" style=\"margin-top:22px\">\n        <div class=\"stat\"><div class=\"n\">24h</div><div class=\"l\">Payment verification</div></div>\n        <div class=\"stat\"><div class=\"n\">48h</div><div class=\"l\">Claims window</div></div>\n        <div class=\"stat\"><div class=\"n\">EA</div><div class=\"l\">East Africa coverage</div></div>\n      </div>\n    </div>\n  </div></section>\n\n  <section class=\"land\" id=\"news\"><div class=\"wrap\">\n    <div class=\"sec-kicker\">Blog &amp; news</div>\n    <h2 class=\"sec-title\">Updates for shippers and carriers</h2>\n    <div class=\"grid3\">\n      <div class=\"news-card\"><span class=\"news-tag\">Routes</span><h3>New corridor: Addis Ababa → Moyale</h3><p>The southern corridor is now open on the load board, with carriers already active on the route.</p><div class=\"news-date\">June 2026</div></div>\n      <div class=\"news-card\"><span class=\"news-tag\">Guidance</span><h3>Documents needed at Galafi &amp; Dewele</h3><p>A quick checklist of paperwork that speeds up border crossing for Djibouti-bound cargo.</p><div class=\"news-date\">May 2026</div></div>\n      <div class=\"news-card\"><span class=\"news-tag\">Platform</span><h3>Manual payment confirmation is live</h3><p>Shippers can now submit bank transfer or cash payment proof, confirmed by our team within 24 hours.</p><div class=\"news-date\">July 2026</div></div>\n    </div>\n  </div></section>\n\n  <footer class=\"land-foot\"><div class=\"wrap foot-in\">\n    <div><b>Ehab Truck Cargo</b> — East Africa Freight Platform · Adama, Ethiopia</div>\n    <div>© 2026 · dispatch@ehabtruck.com</div>\n  </div></footer>\n</div>\n\n<!-- ================= AUTH ================= -->\n<div id=\"authPage\" class=\"hidden\">\n  <div class=\"auth-page\">\n    <div class=\"auth-side\">\n      <div class=\"brand\" style=\"color:#fff\"><img src=\"img/logo-mark.svg\" class=\"brand-mark-img\" alt=\"Ehab Truck\">Ehab<span class=\"red\">Truck</span><span class=\"brand-sub\">Cargo</span></div>\n      <div>\n        <h2>East Africa moves on our trucks.</h2>\n        <p class=\"quote\">One platform for shippers, carriers and dispatch — from Addis Ababa to the ports of Djibouti and Berbera.</p>\n      </div>\n      <img src=\"img/logo.svg\" alt=\"Ehab Truck\" style=\"width:230px;margin-bottom:22px;background:#fff;border-radius:14px;padding:10px 14px\">\n      <div class=\"corridors\">\n        <div><b>910 km</b> — Addis Ababa → Djibouti</div>\n        <div><b>1,050 km</b> — Addis Ababa → Hargeisa</div>\n        <div><b>160 km</b> — Hargeisa → Berbera Port</div>\n      </div>\n    </div>\n    <div class=\"auth-form-wrap\">\n      <div class=\"auth-card\">\n        <h3 id=\"authTitle\">Log in</h3>\n        <div class=\"sub\" id=\"authSub\">Welcome back to Ehab Truck.</div>\n        <div id=\"authErr\" class=\"form-err hidden\"></div>\n        <div id=\"regOnly\" class=\"hidden\">\n          <div class=\"field\"><label>Full name</label><input id=\"fName\" placeholder=\"e.g. Ahmed Mohammed\"></div>\n          <div class=\"field\"><label>Phone</label><input id=\"fPhone\" placeholder=\"+251 9...\"></div>\n          <div class=\"field\"><label>I am a</label>\n            <div class=\"role-picker\">\n              <div class=\"role-opt active\" id=\"roleShipper\" onclick=\"pickRole('shipper')\"><span>📦</span>Shipper<br><small style=\"font-weight:500;color:var(--muted)\">I have cargo</small></div>\n              <div class=\"role-opt\" id=\"roleCarrier\" onclick=\"pickRole('carrier')\"><span>🚛</span>Carrier<br><small style=\"font-weight:500;color:var(--muted)\">I have trucks</small></div>\n            </div>\n          </div>\n        </div>\n        <div class=\"field\"><label>Email</label><input id=\"fEmail\" type=\"email\" placeholder=\"you@example.com\"></div>\n        <div class=\"field\"><label>Password</label><input id=\"fPass\" type=\"password\" placeholder=\"••••••••\" onkeydown=\"if(event.key==='Enter')submitAuth()\"></div>\n        <button class=\"btn block\" id=\"authBtn\" onclick=\"submitAuth()\">Log in</button>\n        <div class=\"auth-switch\"><span id=\"switchTxt\">New to Ehab Truck?</span> <a href=\"#\" onclick=\"toggleAuth();return false\" id=\"switchLink\">Create an account</a></div>\n        <div class=\"auth-switch\" style=\"margin-top:10px\"><a href=\"#\" onclick=\"backToLanding();return false\" style=\"color:var(--muted);font-weight:600\">← Back to website</a></div>\n      </div>\n    </div>\n  </div>\n</div>\n\n<!-- ================= DASHBOARD ================= -->\n<div id=\"dash\" class=\"hidden\">\n  <div class=\"shell\">\n    <aside class=\"sidebar\">\n      <div class=\"brand\"><img src=\"img/logo-mark.svg\" class=\"brand-mark-img\" alt=\"Ehab Truck\">Ehab<span class=\"red\">Truck</span><span class=\"brand-sub\">Cargo</span></div>\n      <div class=\"snav\" id=\"snav\"></div>\n      <div class=\"bottom\">\n        <div class=\"uinfo\"><div class=\"avatar\" id=\"uAvatar\">E</div><div><div class=\"un\" id=\"uName\">—</div><div class=\"ur\" id=\"uRole\">—</div></div></div>\n        <button class=\"btn ghost sm block\" onclick=\"logout()\">Log out</button>\n      </div>\n    </aside>\n    <main class=\"main\" id=\"main\"></main>\n  </div>\n  <div class=\"mobile-tabs\" id=\"mtabs\"></div>\n</div>\n\n<div id=\"modalHost\"></div>\n<div id=\"toastHost\"></div>\n<script src=\"app.js\"></script>\n</body>\n</html>\n","/styles.css":"/* ============================================================\n   EHAB TRUCK — Modern design system (DHL-inspired)\n   ============================================================ */\n:root{\n  --yellow:#FFCC00;\n  --yellow-dark:#F0B90B;\n  --red:#D40511;\n  --ink:#0F172A;\n  --slate:#475569;\n  --muted:#94A3B8;\n  --bg:#F4F6F9;\n  --card:#FFFFFF;\n  --line:#E5EAF0;\n  --green:#16A34A;\n  --blue:#2563EB;\n  --shadow:0 1px 3px rgba(15,23,42,.06),0 8px 24px rgba(15,23,42,.07);\n  --shadow-lg:0 10px 40px rgba(15,23,42,.14);\n  --r:16px;\n}\n*{margin:0;padding:0;box-sizing:border-box}\nhtml{scroll-behavior:smooth}\nbody{font-family:'Inter',system-ui,sans-serif;background:var(--bg);color:var(--ink);line-height:1.55;-webkit-font-smoothing:antialiased}\nh1,h2,h3,.display{font-family:'Plus Jakarta Sans','Inter',sans-serif;font-weight:800;letter-spacing:-.02em}\na{text-decoration:none;color:inherit}\nbutton{font-family:inherit;cursor:pointer;border:none}\ninput,select,textarea{font-family:inherit}\n.hidden{display:none!important}\n.wrap{max-width:1160px;margin:0 auto;padding:0 24px}\n\n/* ---------- Buttons ---------- */\n.btn{display:inline-flex;align-items:center;justify-content:center;gap:8px;background:var(--yellow);color:var(--ink);\n  font-weight:700;font-size:15px;padding:12px 24px;border-radius:12px;transition:.18s;box-shadow:0 2px 8px rgba(240,185,11,.35)}\n.btn:hover{background:var(--yellow-dark);transform:translateY(-1px)}\n.btn:active{transform:translateY(0)}\n.btn.dark{background:var(--ink);color:#fff;box-shadow:none}\n.btn.dark:hover{background:#1E293B}\n.btn.ghost{background:#fff;border:1.5px solid var(--line);box-shadow:none;color:var(--ink)}\n.btn.ghost:hover{border-color:var(--ink)}\n.btn.danger{background:#FEE2E2;color:var(--red);box-shadow:none}\n.btn.success{background:#DCFCE7;color:var(--green);box-shadow:none}\n.btn.sm{padding:8px 14px;font-size:13px;border-radius:10px}\n.btn.block{width:100%}\n.btn:disabled{opacity:.5;cursor:not-allowed;transform:none}\n\n/* ============================================================\n   LANDING\n   ============================================================ */\n.topnav{position:sticky;top:0;z-index:60;background:rgba(255,255,255,.85);backdrop-filter:blur(12px);border-bottom:1px solid var(--line)}\n.topnav-in{display:flex;align-items:center;justify-content:space-between;height:70px}\n.brand{display:flex;align-items:center;gap:10px;font-family:'Plus Jakarta Sans',sans-serif;font-weight:800;font-size:20px}\n.brand-mark{width:38px;height:38px;border-radius:11px;background:linear-gradient(135deg,var(--yellow),var(--yellow-dark));\n  display:grid;place-items:center;font-size:19px;box-shadow:0 3px 10px rgba(240,185,11,.4)}\n.brand .red{color:var(--red)}\n.nav-links{display:flex;gap:28px;font-size:14.5px;font-weight:600;color:var(--slate)}\n.nav-links a:hover{color:var(--ink)}\n\n.hero{position:relative;overflow:hidden;background:\n  radial-gradient(1000px 500px at 85% -10%,rgba(255,204,0,.25),transparent 60%),\n  radial-gradient(700px 400px at -10% 110%,rgba(212,5,17,.07),transparent 60%),#fff}\n.hero-in{display:grid;grid-template-columns:1.15fr .85fr;gap:48px;align-items:center;padding:88px 0 96px}\n.pill{display:inline-flex;align-items:center;gap:8px;background:#FFF8DB;border:1px solid #F5E29A;color:#8a6d00;\n  font-size:13px;font-weight:700;padding:7px 14px;border-radius:999px;margin-bottom:22px}\n.hero h1{font-size:clamp(40px,5.4vw,64px);line-height:1.05}\n.hero h1 .hl{background:linear-gradient(120deg,var(--yellow) 0%,var(--yellow-dark) 100%);border-radius:10px;padding:0 10px;box-decoration-break:clone}\n.hero p.lead{color:var(--slate);font-size:18px;max-width:520px;margin:22px 0 30px}\n.hero-cta{display:flex;gap:14px;flex-wrap:wrap}\n.trustline{display:flex;gap:26px;margin-top:38px;color:var(--slate);font-size:14px;font-weight:600;flex-wrap:wrap}\n.trustline b{color:var(--ink);font-size:20px;font-family:'Plus Jakarta Sans';display:block}\n\n.hero-card{background:var(--card);border:1px solid var(--line);border-radius:22px;box-shadow:var(--shadow-lg);padding:26px}\n.hero-card .hc-title{font-weight:800;font-size:15px;margin-bottom:16px;display:flex;justify-content:space-between;align-items:center}\n.hc-live{display:inline-flex;align-items:center;gap:6px;color:var(--green);font-size:12px;font-weight:700}\n.hc-live::before{content:\"\";width:8px;height:8px;border-radius:50%;background:var(--green);animation:pulse 1.6s infinite}\n@keyframes pulse{50%{opacity:.35}}\n.hc-row{display:flex;justify-content:space-between;align-items:center;padding:13px 0;border-bottom:1px solid var(--line)}\n.hc-row:last-child{border:none}\n.hc-route{font-weight:700;font-size:14.5px}\n.hc-route span{color:var(--muted);font-weight:600;font-size:12.5px;display:block}\n.hc-price{font-family:'Plus Jakarta Sans';font-weight:800;color:var(--ink)}\n.hc-price small{display:block;color:var(--muted);font-weight:600;font-size:11.5px;text-align:right}\n\nsection.land{padding:84px 0}\n.sec-kicker{color:var(--red);font-weight:800;font-size:13px;letter-spacing:2px;text-transform:uppercase}\n.sec-title{font-size:clamp(28px,3.6vw,42px);margin:8px 0 40px}\n.grid3{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:20px}\n.feature{background:var(--card);border:1px solid var(--line);border-radius:var(--r);padding:26px;box-shadow:var(--shadow);transition:.2s}\n.feature:hover{transform:translateY(-3px);box-shadow:var(--shadow-lg)}\n.feature .ic{width:48px;height:48px;border-radius:13px;display:grid;place-items:center;font-size:22px;background:#FFF6D6;margin-bottom:16px}\n.feature h3{font-size:17.5px;margin-bottom:8px}\n.feature p{color:var(--slate);font-size:14.5px}\n.route-strip{display:flex;justify-content:space-between;align-items:center;background:var(--card);border:1px solid var(--line);\n  border-radius:var(--r);padding:20px 24px;box-shadow:var(--shadow);margin-bottom:14px;flex-wrap:wrap;gap:12px}\n.route-strip .rt{font-family:'Plus Jakarta Sans';font-weight:800;font-size:17px;display:flex;align-items:center;gap:10px}\n.route-strip .rt .arr{color:var(--red)}\n.route-strip .rmeta{display:flex;gap:24px;color:var(--slate);font-size:13.5px;font-weight:600}\n.route-strip .rmeta b{color:var(--ink)}\n.cta-band{background:linear-gradient(120deg,var(--ink) 0%,#1E293B 100%);border-radius:24px;padding:56px;display:flex;\n  justify-content:space-between;align-items:center;gap:24px;flex-wrap:wrap;color:#fff;position:relative;overflow:hidden}\n.cta-band::after{content:\"🚛\";position:absolute;font-size:170px;right:-20px;bottom:-45px;opacity:.12}\n.cta-band h2{font-size:clamp(24px,3vw,36px)}\n.cta-band p{color:#CBD5E1;margin-top:8px}\nfooter.land-foot{padding:36px 0;color:var(--muted);font-size:14px;border-top:1px solid var(--line);background:#fff}\n.foot-in{display:flex;justify-content:space-between;flex-wrap:wrap;gap:14px}\n\n/* ============================================================\n   AUTH\n   ============================================================ */\n.auth-page{min-height:100vh;display:grid;grid-template-columns:1fr 1fr}\n.auth-side{background:linear-gradient(160deg,#111827 0%,#1E293B 100%);color:#fff;padding:56px;display:flex;flex-direction:column;justify-content:space-between;position:relative;overflow:hidden}\n.auth-side::after{content:\"\";position:absolute;inset:auto -80px -80px auto;width:340px;height:340px;border-radius:50%;background:radial-gradient(circle,rgba(255,204,0,.3),transparent 70%)}\n.auth-side h2{font-size:34px;line-height:1.15;margin-top:40px}\n.auth-side .quote{color:#CBD5E1;font-size:15px;max-width:400px;margin-top:16px}\n.auth-side .corridors{display:flex;flex-direction:column;gap:10px;margin-top:auto;font-size:14px;color:#CBD5E1}\n.auth-side .corridors b{color:var(--yellow)}\n.auth-form-wrap{display:flex;align-items:center;justify-content:center;padding:40px;background:var(--bg)}\n.auth-card{width:100%;max-width:420px;background:var(--card);border:1px solid var(--line);border-radius:22px;box-shadow:var(--shadow-lg);padding:34px}\n.auth-card h3{font-size:24px;margin-bottom:4px}\n.auth-card .sub{color:var(--slate);font-size:14px;margin-bottom:22px}\n.field{margin-bottom:16px}\n.field label{display:block;font-size:13px;font-weight:700;color:var(--slate);margin-bottom:7px}\n.field input,.field select{width:100%;background:#fff;border:1.5px solid var(--line);border-radius:12px;padding:12px 14px;font-size:15px;transition:.15s}\n.field input:focus,.field select:focus{outline:none;border-color:var(--yellow-dark);box-shadow:0 0 0 4px rgba(255,204,0,.18)}\n.role-picker{display:grid;grid-template-columns:1fr 1fr;gap:10px}\n.role-opt{border:1.5px solid var(--line);border-radius:12px;padding:12px;text-align:center;font-weight:700;font-size:13.5px;cursor:pointer;background:#fff;transition:.15s}\n.role-opt.active{border-color:var(--yellow-dark);background:#FFFBEB;box-shadow:0 0 0 3px rgba(255,204,0,.15)}\n.role-opt span{display:block;font-size:20px;margin-bottom:4px}\n.form-err{background:#FEF2F2;color:var(--red);border:1px solid #FECACA;font-size:13.5px;font-weight:600;padding:10px 14px;border-radius:10px;margin-bottom:14px}\n.auth-switch{margin-top:18px;font-size:14px;color:var(--slate);text-align:center}\n.auth-switch a{color:var(--red);font-weight:700}\n\n/* ============================================================\n   DASHBOARD SHELL\n   ============================================================ */\n.shell{display:grid;grid-template-columns:250px 1fr;min-height:100vh}\n.sidebar{background:var(--ink);color:#CBD5E1;padding:22px 16px;display:flex;flex-direction:column;position:sticky;top:0;height:100vh}\n.sidebar .brand{color:#fff;padding:6px 10px 22px;font-size:18px}\n.snav{display:flex;flex-direction:column;gap:4px}\n.snav button{display:flex;align-items:center;gap:12px;background:none;color:#CBD5E1;font-size:14.5px;font-weight:600;\n  padding:12px 14px;border-radius:12px;text-align:left;transition:.15s;width:100%}\n.snav button:hover{background:rgba(255,255,255,.07);color:#fff}\n.snav button.active{background:var(--yellow);color:var(--ink);font-weight:700;box-shadow:0 3px 12px rgba(255,204,0,.3)}\n.sidebar .bottom{margin-top:auto;border-top:1px solid rgba(255,255,255,.1);padding-top:16px}\n.uinfo{display:flex;gap:10px;align-items:center;padding:8px 10px;margin-bottom:8px}\n.avatar{width:38px;height:38px;border-radius:50%;background:var(--yellow);color:var(--ink);display:grid;place-items:center;font-weight:800;font-size:15px}\n.uinfo .un{font-size:14px;font-weight:700;color:#fff}\n.uinfo .ur{font-size:11.5px;color:var(--muted);text-transform:capitalize}\n\n.main{padding:28px 32px 60px;min-width:0}\n.page-head{display:flex;justify-content:space-between;align-items:center;gap:16px;flex-wrap:wrap;margin-bottom:26px}\n.page-head h2{font-size:26px}\n.page-head .sub{color:var(--slate);font-size:14px;margin-top:2px}\n.searchbar{display:flex;align-items:center;gap:10px;background:#fff;border:1.5px solid var(--line);border-radius:12px;padding:10px 14px;min-width:260px}\n.searchbar input{border:none;outline:none;font-size:14.5px;flex:1;background:none}\n\n/* KPI cards */\n.kpis{display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:16px;margin-bottom:28px}\n.kpi{background:var(--card);border:1px solid var(--line);border-radius:var(--r);padding:20px;box-shadow:var(--shadow);position:relative;overflow:hidden}\n.kpi::before{content:\"\";position:absolute;top:0;left:0;right:0;height:4px;background:var(--yellow)}\n.kpi.k-red::before{background:var(--red)}\n.kpi.k-green::before{background:var(--green)}\n.kpi.k-blue::before{background:var(--blue)}\n.kpi .kn{font-family:'Plus Jakarta Sans';font-weight:800;font-size:30px;margin-top:6px}\n.kpi .kl{color:var(--slate);font-size:13px;font-weight:600}\n\n/* Load cards & table */\n.load-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(330px,1fr));gap:18px}\n.lcard{background:var(--card);border:1px solid var(--line);border-radius:var(--r);box-shadow:var(--shadow);padding:20px;display:flex;flex-direction:column;gap:12px;transition:.18s}\n.lcard:hover{box-shadow:var(--shadow-lg);transform:translateY(-2px)}\n.lcard .top{display:flex;justify-content:space-between;align-items:flex-start;gap:10px}\n.lroute{font-family:'Plus Jakarta Sans';font-weight:800;font-size:17px}\n.lroute .arr{color:var(--red)}\n.lid{color:var(--muted);font-size:12px;font-weight:700}\n.lmeta{display:grid;grid-template-columns:1fr 1fr;gap:6px 14px;font-size:13.5px;color:var(--slate)}\n.lmeta b{color:var(--ink);font-weight:700}\n.lprice{font-family:'Plus Jakarta Sans';font-weight:800;font-size:21px}\n.lprice small{color:var(--muted);font-size:12.5px;font-weight:600;margin-left:6px}\n.badge{font-size:11px;font-weight:800;letter-spacing:.4px;text-transform:uppercase;padding:5px 11px;border-radius:999px;white-space:nowrap}\n.b-posted{background:#DBEAFE;color:var(--blue)}\n.b-booked{background:#FEF3C7;color:#92400E}\n.b-transit{background:#DCFCE7;color:var(--green)}\n.b-delivered{background:#E2E8F0;color:var(--slate)}\n.progress{display:flex;gap:5px}\n.progress i{flex:1;height:6px;border-radius:99px;background:var(--line)}\n.progress i.on{background:var(--yellow-dark)}\n.lactions{display:flex;gap:8px;flex-wrap:wrap}\n.empty{background:var(--card);border:1.5px dashed var(--line);border-radius:var(--r);padding:56px 20px;text-align:center;color:var(--slate)}\n.empty .big{font-size:38px;margin-bottom:10px}\n\n.tablecard{background:var(--card);border:1px solid var(--line);border-radius:var(--r);box-shadow:var(--shadow);overflow:auto}\ntable{width:100%;border-collapse:collapse;font-size:14px;min-width:640px}\nth{text-align:left;font-size:12px;text-transform:uppercase;letter-spacing:.6px;color:var(--muted);padding:14px 18px;border-bottom:1px solid var(--line);background:#FAFBFC}\ntd{padding:14px 18px;border-bottom:1px solid var(--line)}\ntr:last-child td{border-bottom:none}\n\n/* Modal & toast */\n.modal-bg{position:fixed;inset:0;background:rgba(15,23,42,.5);backdrop-filter:blur(3px);display:flex;align-items:center;justify-content:center;z-index:100;padding:18px}\n.modal{background:#fff;border-radius:20px;box-shadow:var(--shadow-lg);padding:30px;max-width:480px;width:100%;max-height:92vh;overflow:auto}\n.modal h3{font-size:21px;margin-bottom:18px}\n.toast{position:fixed;bottom:24px;left:50%;transform:translateX(-50%);background:var(--ink);color:#fff;font-weight:600;\n  font-size:14.5px;padding:13px 22px;border-radius:14px;z-index:200;box-shadow:var(--shadow-lg);display:flex;gap:10px;align-items:center;animation:toastin .25s}\n@keyframes toastin{from{opacity:0;transform:translate(-50%,12px)}}\n.toast .dot{width:9px;height:9px;border-radius:50%;background:var(--yellow)}\n\n/* Map */\n.mapbox{height:540px;border-radius:var(--r);border:1px solid var(--line);box-shadow:var(--shadow);overflow:hidden;background:#E8EDF2}\n.map-legend{display:flex;gap:18px;flex-wrap:wrap;margin:14px 0 0;font-size:13px;font-weight:600;color:var(--slate)}\n.map-legend span{display:inline-flex;align-items:center;gap:7px}\n.map-legend i{width:22px;height:4px;border-radius:99px;display:inline-block}\n.leaflet-popup-content{font-family:'Inter',sans-serif;font-size:13.5px}\n.leaflet-popup-content b{font-family:'Plus Jakarta Sans'}\n\n/* Order detail timeline */\n.timeline{margin-top:6px}\n.tl-item{display:flex;gap:14px;position:relative;padding-bottom:20px}\n.tl-item:last-child{padding-bottom:0}\n.tl-item::before{content:\"\";position:absolute;left:9px;top:22px;bottom:0;width:2px;background:var(--line)}\n.tl-item:last-child::before{display:none}\n.tl-dot{width:20px;height:20px;border-radius:50%;background:#fff;border:3px solid var(--line);flex-shrink:0;z-index:1}\n.tl-item.done .tl-dot{border-color:var(--yellow-dark);background:var(--yellow)}\n.tl-body .tl-st{font-weight:800;font-size:14.5px}\n.tl-body .tl-time{color:var(--muted);font-size:12.5px;font-weight:600}\n.detail-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px 18px;margin:16px 0;font-size:14px}\n.detail-grid .dl{color:var(--muted);font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.4px}\n.detail-grid .dv{font-weight:700}\n.modal .close-x{float:right;background:var(--bg);border-radius:10px;width:34px;height:34px;font-size:16px;font-weight:700}\n\n/* Mobile */\n.mobile-tabs{display:none}\n@media(max-width:960px){\n  .hero-in{grid-template-columns:1fr;padding:56px 0 64px}\n  .auth-page{grid-template-columns:1fr}\n  .auth-side{display:none}\n  .shell{grid-template-columns:1fr}\n  .sidebar{display:none}\n  .main{padding:20px 16px 90px}\n  .mobile-tabs{display:flex;position:fixed;bottom:0;left:0;right:0;background:#fff;border-top:1px solid var(--line);z-index:80;box-shadow:0 -6px 20px rgba(15,23,42,.08)}\n  .mobile-tabs button{flex:1;background:none;padding:10px 4px 12px;font-size:11px;font-weight:700;color:var(--slate);display:flex;flex-direction:column;gap:3px;align-items:center}\n  .mobile-tabs button.active{color:var(--ink)}\n  .mobile-tabs button .mi{font-size:20px}\n  .mobile-tabs button.active .mi{filter:drop-shadow(0 2px 6px rgba(255,204,0,.6))}\n  .nav-links{display:none}\n}\n@media (prefers-reduced-motion:reduce){*{animation:none!important;transition:none!important}}\n\n/* Brand logo image + photo gallery */\n.brand-mark-img{width:38px;height:38px;border-radius:11px;box-shadow:0 3px 10px rgba(240,185,11,.4)}\n.photo-card{background:var(--card);border:1px solid var(--line);border-radius:var(--r);overflow:hidden;box-shadow:var(--shadow);margin:0}\n.photo-card img{width:100%;display:block;aspect-ratio:16/9;object-fit:cover}\n.photo-card figcaption{padding:14px 18px;font-size:14px;font-weight:600;color:var(--slate)}\n\n/* Brand subtitle \"Cargo\" */\n.brand-sub{font-size:12px;font-weight:700;color:var(--slate);margin-left:5px;letter-spacing:.5px;text-transform:uppercase;align-self:flex-end;padding-bottom:2px}\n.brand{align-items:flex-end}\n\n/* Policy & News sections */\n.policy-card{background:var(--card);border:1px solid var(--line);border-radius:var(--r);padding:26px;box-shadow:var(--shadow)}\n.policy-list{list-style:none;margin:16px 0;display:grid;gap:10px}\n.policy-list li{display:flex;gap:10px;font-size:14.5px;color:var(--slate)}\n.policy-list li b{color:var(--ink)}\n.news-card{background:var(--card);border:1px solid var(--line);border-radius:var(--r);padding:22px;box-shadow:var(--shadow);transition:.2s}\n.news-card:hover{transform:translateY(-3px);box-shadow:var(--shadow-lg)}\n.news-tag{display:inline-block;background:#FFF6D6;color:#8a6d00;font-size:11.5px;font-weight:800;text-transform:uppercase;letter-spacing:.5px;padding:4px 10px;border-radius:999px;margin-bottom:10px}\n.news-card h3{font-size:16.5px;margin-bottom:8px}\n.news-card p{color:var(--slate);font-size:14px}\n.news-date{color:var(--muted);font-size:12.5px;font-weight:600;margin-top:10px}\n","/":"<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Ehab Truck Cargo — East Africa Freight & Load Board</title>\n<meta name=\"description\" content=\"Post loads and book trucks across Ethiopia, Djibouti and Somalia. Full truck load, live tracking, transparent ETB/USD pricing.\">\n<meta name=\"theme-color\" content=\"#FFCC00\">\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n<link href=\"https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@600;700;800&family=Inter:wght@400;500;600;700&display=swap\" rel=\"stylesheet\">\n<link rel=\"icon\" type=\"image/svg+xml\" href=\"img/logo-mark.svg\">\n<link rel=\"stylesheet\" href=\"styles.css\">\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.css\">\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.js\"></script>\n</head>\n<body>\n\n<!-- ================= LANDING ================= -->\n<div id=\"landing\">\n  <nav class=\"topnav\"><div class=\"wrap topnav-in\">\n    <div class=\"brand\"><img src=\"img/logo-mark.svg\" class=\"brand-mark-img\" alt=\"Ehab Truck\">Ehab<span class=\"red\">Truck</span><span class=\"brand-sub\">Cargo</span></div>\n    <div class=\"nav-links\">\n      <a href=\"#routes\">Routes</a><a href=\"#features\">Platform</a><a href=\"#fleet\">Fleet</a><a href=\"#how\">How it works</a><a href=\"#policy\">Policy</a><a href=\"#news\">News</a>\n    </div>\n    <div style=\"display:flex;gap:10px\">\n      <button class=\"btn ghost\" onclick=\"showAuth('login')\">Log in</button>\n      <button class=\"btn\" onclick=\"showAuth('register')\">Get started</button>\n    </div>\n  </div></nav>\n\n  <header class=\"hero\"><div class=\"wrap hero-in\">\n    <div>\n      <span class=\"pill\">🇪🇹 Ethiopia · 🇩🇯 Djibouti · 🇸🇴 Somalia</span>\n      <h1>The load board for the <span class=\"hl\">Horn of Africa</span></h1>\n      <p class=\"lead\">Ehab Truck connects cargo owners with verified truck operators. Post a load in one minute, book a truck in one click, and track every kilometre to delivery.</p>\n      <div class=\"hero-cta\">\n        <button class=\"btn\" onclick=\"showAuth('register','shipper')\">Post a load — free</button>\n        <button class=\"btn dark\" onclick=\"showAuth('register','carrier')\">Drive with us</button>\n      </div>\n      <div class=\"trustline\">\n        <div><b>6+</b>Daily corridors</div>\n        <div><b>3</b>Countries</div>\n        <div><b>24/7</b>Dispatch</div>\n        <div><b>0 ETB</b>Posting fee</div>\n      </div>\n    </div>\n    <div class=\"hero-card\">\n      <div class=\"hc-title\">Load board <span class=\"hc-live\">Live</span></div>\n      <div class=\"hc-row\"><div class=\"hc-route\">Addis Ababa → Djibouti<span>Coffee · 24 t · 40ft</span></div><div class=\"hc-price\">185,000 ETB<small>≈ $1,450</small></div></div>\n      <div class=\"hc-row\"><div class=\"hc-route\">Dire Dawa → Djibouti<span>Perishables · 8 t · Reefer</span></div><div class=\"hc-price\">95,000 ETB<small>≈ $740</small></div></div>\n      <div class=\"hc-row\"><div class=\"hc-route\">Addis Ababa → Hargeisa<span>Electronics · 12 t · Box</span></div><div class=\"hc-price\">210,000 ETB<small>≈ $1,640</small></div></div>\n      <div class=\"hc-row\"><div class=\"hc-route\">Hargeisa → Berbera<span>Containers · Port link</span></div><div class=\"hc-price\">48,000 ETB<small>≈ $375</small></div></div>\n      <img src=\"img/sample-highway.svg\" alt=\"Ehab Truck on the highway\" style=\"width:100%;border-radius:18px;margin-top:16px;box-shadow:var(--shadow-lg)\">\n    </div>\n  </div></header>\n\n  <section class=\"land\" id=\"routes\"><div class=\"wrap\">\n    <div class=\"sec-kicker\">Corridors</div>\n    <h2 class=\"sec-title\">Routes we run every day</h2>\n    <div class=\"route-strip\"><div class=\"rt\">Addis Ababa <span class=\"arr\">→</span> Djibouti</div><div class=\"rmeta\"><span>Distance <b>~910 km</b></span><span>Transit <b>2–3 days</b></span><span><b>Import/Export corridor</b></span></div></div>\n    <div class=\"route-strip\"><div class=\"rt\">Adama <span class=\"arr\">→</span> Djibouti</div><div class=\"rmeta\"><span>Distance <b>~815 km</b></span><span>Transit <b>2 days</b></span><span><b>Containers & fuel</b></span></div></div>\n    <div class=\"route-strip\"><div class=\"rt\">Dire Dawa <span class=\"arr\">→</span> Djibouti</div><div class=\"rmeta\"><span>Distance <b>~440 km</b></span><span>Transit <b>1 day</b></span><span><b>Fast lane</b></span></div></div>\n    <div class=\"route-strip\"><div class=\"rt\">Addis Ababa <span class=\"arr\">→</span> Hargeisa</div><div class=\"rmeta\"><span>Distance <b>~1,050 km</b></span><span>Transit <b>3 days</b></span><span><b>Via Tog Wajaale</b></span></div></div>\n    <div class=\"route-strip\"><div class=\"rt\">Hargeisa <span class=\"arr\">→</span> Berbera</div><div class=\"rmeta\"><span>Distance <b>~160 km</b></span><span>Transit <b>Same day</b></span><span><b>Berbera Port link</b></span></div></div>\n    <div class=\"route-strip\"><div class=\"rt\">Addis Ababa <span class=\"arr\">→</span> Moyale</div><div class=\"rmeta\"><span>Distance <b>~775 km</b></span><span>Transit <b>2–3 days</b></span><span><b>Southern corridor</b></span></div></div>\n  </div></section>\n\n  <section class=\"land\" id=\"features\" style=\"background:#fff\"><div class=\"wrap\">\n    <div class=\"sec-kicker\">Platform</div>\n    <h2 class=\"sec-title\">Built like the big freight platforms</h2>\n    <div class=\"grid3\">\n      <div class=\"feature\"><div class=\"ic\">📦</div><h3>Smart load board</h3><p>Live marketplace where shippers post full truck loads and verified carriers book instantly — no phone chains, no middlemen.</p></div>\n      <div class=\"feature\"><div class=\"ic\">🛰️</div><h3>Shipment tracking</h3><p>Every load moves through Posted → Booked → In Transit → Delivered, with a timestamped history for every step.</p></div>\n      <div class=\"feature\"><div class=\"ic\">💰</div><h3>ETB + USD pricing</h3><p>Every price is shown in Ethiopian Birr and US Dollars before booking. Nothing changes at the border or the port.</p></div>\n      <div class=\"feature\"><div class=\"ic\">✅</div><h3>Verified carriers</h3><p>Truck operators are reviewed and approved by the Ehab team before they can accept their first load.</p></div>\n      <div class=\"feature\"><div class=\"ic\">🛃</div><h3>Border expertise</h3><p>Daily operations through Galafi, Dewele and Tog Wajaale crossings, plus Djibouti and Berbera port handling.</p></div>\n      <div class=\"feature\"><div class=\"ic\">📊</div><h3>Real dashboard</h3><p>Shippers, carriers and admins each get a purpose-built dashboard with live KPIs — not a spreadsheet.</p></div>\n    </div>\n  </div></section>\n\n  <section class=\"land\" id=\"fleet\" style=\"background:#fff\"><div class=\"wrap\">\n    <div class=\"sec-kicker\">Our operation</div>\n    <h2 class=\"sec-title\">From depot to port</h2>\n    <div class=\"grid3\">\n      <figure class=\"photo-card\"><img src=\"img/sample-highway.svg\" alt=\"Ehab truck on the Addis–Djibouti highway\">\n        <figcaption>On the Addis Ababa – Djibouti corridor</figcaption></figure>\n      <figure class=\"photo-card\"><img src=\"img/sample-port.svg\" alt=\"Container handling at the port\">\n        <figcaption>Container handling — Djibouti &amp; Berbera ports</figcaption></figure>\n      <figure class=\"photo-card\"><img src=\"img/sample-warehouse.svg\" alt=\"Cargo depot loading\">\n        <figcaption>Loading at the Adama cargo depot</figcaption></figure>\n    </div>\n  </div></section>\n\n  <section class=\"land\" id=\"how\"><div class=\"wrap\">\n    <div class=\"sec-kicker\">How it works</div>\n    <h2 class=\"sec-title\">From posting to delivery</h2>\n    <div class=\"grid3\">\n      <div class=\"feature\"><div class=\"ic\">1️⃣</div><h3>Post your load</h3><p>Route, cargo, truck type, pickup date and your price in ETB. Takes one minute, costs nothing.</p></div>\n      <div class=\"feature\"><div class=\"ic\">2️⃣</div><h3>A carrier books it</h3><p>Verified truck operators see your load on the board and book it in one click. You see who's carrying your cargo.</p></div>\n      <div class=\"feature\"><div class=\"ic\">3️⃣</div><h3>Track to delivery</h3><p>The carrier updates the trip status live. You watch your cargo move from pickup to delivered.</p></div>\n    </div>\n    <div style=\"margin-top:56px\">\n      <div class=\"cta-band\">\n        <div><h2>Ready to move cargo?</h2><p>Join Ehab Truck today — free for shippers.</p></div>\n        <button class=\"btn\" onclick=\"showAuth('register')\">Create free account</button>\n      </div>\n    </div>\n  </div></section>\n\n  <section class=\"land\" id=\"policy\" style=\"background:#fff\"><div class=\"wrap\">\n    <div class=\"sec-kicker\">Important customer document</div>\n    <h2 class=\"sec-title\">Service policy</h2>\n    <div class=\"policy-card\">\n      <p style=\"color:var(--slate);font-size:15px;max-width:640px\">Read our booking rules, payment verification process, cargo handling guidelines, and route coverage before placing a shipment.</p>\n      <ul class=\"policy-list\">\n        <li>📋 <div><b>Booking requirements</b> — accurate cargo description, weight, and pickup date required at posting.</div></li>\n        <li>💳 <div><b>Payment rules</b> — payments are confirmed manually by admin after bank transfer, cash, or mobile money; verification usually completes within 24 hours.</div></li>\n        <li>📦 <div><b>Claims process</b> — report any cargo damage or delay through Contact within 48 hours of delivery.</div></li>\n        <li>📞 <div><b>Support contacts</b> — dispatch is reachable by phone/WhatsApp during business hours, 7 days a week.</div></li>\n      </ul>\n      <div class=\"stats\" style=\"margin-top:22px\">\n        <div class=\"stat\"><div class=\"n\">24h</div><div class=\"l\">Payment verification</div></div>\n        <div class=\"stat\"><div class=\"n\">48h</div><div class=\"l\">Claims window</div></div>\n        <div class=\"stat\"><div class=\"n\">EA</div><div class=\"l\">East Africa coverage</div></div>\n      </div>\n    </div>\n  </div></section>\n\n  <section class=\"land\" id=\"news\"><div class=\"wrap\">\n    <div class=\"sec-kicker\">Blog &amp; news</div>\n    <h2 class=\"sec-title\">Updates for shippers and carriers</h2>\n    <div class=\"grid3\">\n      <div class=\"news-card\"><span class=\"news-tag\">Routes</span><h3>New corridor: Addis Ababa → Moyale</h3><p>The southern corridor is now open on the load board, with carriers already active on the route.</p><div class=\"news-date\">June 2026</div></div>\n      <div class=\"news-card\"><span class=\"news-tag\">Guidance</span><h3>Documents needed at Galafi &amp; Dewele</h3><p>A quick checklist of paperwork that speeds up border crossing for Djibouti-bound cargo.</p><div class=\"news-date\">May 2026</div></div>\n      <div class=\"news-card\"><span class=\"news-tag\">Platform</span><h3>Manual payment confirmation is live</h3><p>Shippers can now submit bank transfer or cash payment proof, confirmed by our team within 24 hours.</p><div class=\"news-date\">July 2026</div></div>\n    </div>\n  </div></section>\n\n  <footer class=\"land-foot\"><div class=\"wrap foot-in\">\n    <div><b>Ehab Truck Cargo</b> — East Africa Freight Platform · Adama, Ethiopia</div>\n    <div>© 2026 · dispatch@ehabtruck.com</div>\n  </div></footer>\n</div>\n\n<!-- ================= AUTH ================= -->\n<div id=\"authPage\" class=\"hidden\">\n  <div class=\"auth-page\">\n    <div class=\"auth-side\">\n      <div class=\"brand\" style=\"color:#fff\"><img src=\"img/logo-mark.svg\" class=\"brand-mark-img\" alt=\"Ehab Truck\">Ehab<span class=\"red\">Truck</span><span class=\"brand-sub\">Cargo</span></div>\n      <div>\n        <h2>East Africa moves on our trucks.</h2>\n        <p class=\"quote\">One platform for shippers, carriers and dispatch — from Addis Ababa to the ports of Djibouti and Berbera.</p>\n      </div>\n      <img src=\"img/logo.svg\" alt=\"Ehab Truck\" style=\"width:230px;margin-bottom:22px;background:#fff;border-radius:14px;padding:10px 14px\">\n      <div class=\"corridors\">\n        <div><b>910 km</b> — Addis Ababa → Djibouti</div>\n        <div><b>1,050 km</b> — Addis Ababa → Hargeisa</div>\n        <div><b>160 km</b> — Hargeisa → Berbera Port</div>\n      </div>\n    </div>\n    <div class=\"auth-form-wrap\">\n      <div class=\"auth-card\">\n        <h3 id=\"authTitle\">Log in</h3>\n        <div class=\"sub\" id=\"authSub\">Welcome back to Ehab Truck.</div>\n        <div id=\"authErr\" class=\"form-err hidden\"></div>\n        <div id=\"regOnly\" class=\"hidden\">\n          <div class=\"field\"><label>Full name</label><input id=\"fName\" placeholder=\"e.g. Ahmed Mohammed\"></div>\n          <div class=\"field\"><label>Phone</label><input id=\"fPhone\" placeholder=\"+251 9...\"></div>\n          <div class=\"field\"><label>I am a</label>\n            <div class=\"role-picker\">\n              <div class=\"role-opt active\" id=\"roleShipper\" onclick=\"pickRole('shipper')\"><span>📦</span>Shipper<br><small style=\"font-weight:500;color:var(--muted)\">I have cargo</small></div>\n              <div class=\"role-opt\" id=\"roleCarrier\" onclick=\"pickRole('carrier')\"><span>🚛</span>Carrier<br><small style=\"font-weight:500;color:var(--muted)\">I have trucks</small></div>\n            </div>\n          </div>\n        </div>\n        <div class=\"field\"><label>Email</label><input id=\"fEmail\" type=\"email\" placeholder=\"you@example.com\"></div>\n        <div class=\"field\"><label>Password</label><input id=\"fPass\" type=\"password\" placeholder=\"••••••••\" onkeydown=\"if(event.key==='Enter')submitAuth()\"></div>\n        <button class=\"btn block\" id=\"authBtn\" onclick=\"submitAuth()\">Log in</button>\n        <div class=\"auth-switch\"><span id=\"switchTxt\">New to Ehab Truck?</span> <a href=\"#\" onclick=\"toggleAuth();return false\" id=\"switchLink\">Create an account</a></div>\n        <div class=\"auth-switch\" style=\"margin-top:10px\"><a href=\"#\" onclick=\"backToLanding();return false\" style=\"color:var(--muted);font-weight:600\">← Back to website</a></div>\n      </div>\n    </div>\n  </div>\n</div>\n\n<!-- ================= DASHBOARD ================= -->\n<div id=\"dash\" class=\"hidden\">\n  <div class=\"shell\">\n    <aside class=\"sidebar\">\n      <div class=\"brand\"><img src=\"img/logo-mark.svg\" class=\"brand-mark-img\" alt=\"Ehab Truck\">Ehab<span class=\"red\">Truck</span><span class=\"brand-sub\">Cargo</span></div>\n      <div class=\"snav\" id=\"snav\"></div>\n      <div class=\"bottom\">\n        <div class=\"uinfo\"><div class=\"avatar\" id=\"uAvatar\">E</div><div><div class=\"un\" id=\"uName\">—</div><div class=\"ur\" id=\"uRole\">—</div></div></div>\n        <button class=\"btn ghost sm block\" onclick=\"logout()\">Log out</button>\n      </div>\n    </aside>\n    <main class=\"main\" id=\"main\"></main>\n  </div>\n  <div class=\"mobile-tabs\" id=\"mtabs\"></div>\n</div>\n\n<div id=\"modalHost\"></div>\n<div id=\"toastHost\"></div>\n<script src=\"app.js\"></script>\n</body>\n</html>\n"};

const MIME = { ".html": "text/html", ".css": "text/css", ".js": "text/javascript", ".png": "image/png", ".svg": "image/svg+xml", ".json": "application/json", ".ico": "image/x-icon" };
function ext(p){ const i = p.lastIndexOf("."); return i<0?"":p.slice(i); }
function serveStatic(req, res, url) {
  let p = url.pathname === "/" ? "/" : url.pathname;
  let content = FILES[p];
  if (content === undefined) content = FILES["/"];
  const type = p === "/" ? "text/html" : (MIME[ext(p)] || "text/html");
  res.writeHead(200, { "Content-Type": type });
  res.end(content);
}

/* ---------------- SERVER ---------------- */
load();
http.createServer((req, res) => {
  const url = new URL(req.url, "http://x");
  if (url.pathname.startsWith("/api/")) return api(req, res, url).catch(e => json(res, 500, { error: "Server error: " + e.message }));
  serveStatic(req, res, url);
}).listen(PORT, () => {
  console.log("=========================================");
  console.log("  EHAB TRUCK CARGO server running");
  console.log("  Open:  http://localhost:" + PORT);
  console.log("  Admin: admin@ehab.com / admin123");
  console.log("  Data:  " + DATA_FILE);
  console.log("=========================================");
});
